    if (!text.trim()) { setError("Vui lòng nhập văn bản cần đọc."); return; }
    setError(null); setLoading(true); setAudioUrl(null);
    try {
      const base64Audio = await generateSpeech({ text, voiceId: selectedVoice.apiId, speed });
      if (!base64Audio) throw new Error("Không nhận được dữ liệu âm thanh.");

