  };

  // Utils
  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
  };

  return (
    <div className="h-full bg-gradient-to-br from-orange-50 via-white to-amber-50 p-4 font-body text-slate-800 lg:overflow-y-auto custom-scrollbar">
      <div className="max-w-5xl mx-auto">

        {/* Header */}
        <div className="text-center mb-8">
          <div className="inline-flex items-center justify-center w-16 h-16 bg-white rounded-2xl shadow-lg mb-4 text-orange-500 border border-orange-100">
