export const decodeAudioData = async (base64String: string, audioContext: AudioContext): Promise<AudioBuffer> => {
  const binaryString = atob(base64String);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }

  const sampleRate = 24000;
  const numChannels = 1;

  const dataInt16 = new Int16Array(bytes.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = audioContext.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export const audioBufferToWav = (buffer: AudioBuffer): Blob => {
  const numOfChan = buffer.numberOfChannels;
  const length = buffer.length * numOfChan * 2 + 44;
  const bufferArr = new ArrayBuffer(length);
  const view = new DataView(bufferArr);
  const channels = [];
  let i;
  let sample;
  let offset = 0;
  let pos = 0;

  setUint32(0x46464952); // "RIFF"
  setUint32(length - 8); // file length - 8
  setUint32(0x45564157); // "WAVE"

  setUint32(0x20746d66); // "fmt " chunk
  setUint32(16); // length = 16
  setUint16(1); // PCM (uncompressed)
  setUint16(numOfChan);
  setUint32(buffer.sampleRate);
  setUint32(buffer.sampleRate * 2 * numOfChan); // avg. bytes/sec
  setUint16(numOfChan * 2); // block-align
  setUint16(16); // 16-bit (hardcoded in this function)

  setUint32(0x61746164); // "data" - chunk
  setUint32(length - pos - 4); // chunk length

  for(i = 0; i < buffer.numberOfChannels; i++)
    channels.push(buffer.getChannelData(i));

  while(pos < buffer.length) {
    for(i = 0; i < numOfChan; i++) {             // interleave channels
      sample = Math.max(-1, Math.min(1, channels[i][pos])); // clamp
      sample = (0.5 + sample < 0 ? sample * 32768 : sample * 32767)|0; // scale to 16-bit signed int
      view.setInt16(44 + offset, sample, true);          // write 16-bit sample
      offset += 2;
    }
    pos++;
  }

  return new Blob([bufferArr], {type: 'audio/wav'});

  function setUint16(data: any) {
    view.setUint16(pos, data, true);
    pos += 2;
  }

  function setUint32(data: any) {
    view.setUint32(pos, data, true);
    pos += 4;
  }
}

export const generateMarketingImage = async (
  productImg: ProcessedImage,
  faceImg: ProcessedImage | null,
  productName: string,
  feedback: string,
  aspectRatio: string = "9:16"
): Promise<string> => {

  const parts: any[] = [
    {
      inlineData: {
        data: productImg.base64,
        mimeType: productImg.mimeType
      }
    }
  ];

  if (faceImg) {
    parts.push({
      inlineData: {
        data: faceImg.base64,
        mimeType: faceImg.mimeType
      }
    });
  }

  let prompt = `Generate a high-quality photorealistic commercial image (Sony A7II style, 85mm f/1.8 lens).

  CORE TASK:
  Synthesize the provided product image and face image (if present) into a cohesive professional marketing photo.

  DETAILS:
  1. PRODUCT FIDELITY (TOP PRIORITY): 
     - The product '${productName}' must be the focal point.
     - PRESERVE THE EXACT APPEARANCE of the product from the input image. 
     - DO NOT MODIFY, ADD, OR REMOVE details (logos, text, shape, cap, color).
  2. SCALE & PROPORTION (CRITICAL - REALISTIC SIZE): 
     - ANALYZE the product type (e.g., perfume, shampoo, machine) to determine its real-world size.
     - RESIZE the product relative to the model's hands and face to be PHYSICALLY ACCURATE. 
     - It MUST NOT be oversized or giant. The product should look balanced with the human figure.
  3. MODEL: Use the provided face for the model. Skin texture must be ultra-realistic.
  4. INTERACTION: The model holds the product naturally. Hand positioning must be physically accurate. Fingers must wrap around the object correctly based on its size.
  5. LIGHTING: Cinematic studio softbox lighting. Soft background bokeh.
  6. COMPOSITION: Vertical (9:16), centered, balanced for social media ads.

  NEGATIVE PROMPT:
  giant product, oversized product, tiny hands, distorted hands, extra fingers, bad anatomy, plastic skin, cartoon, low quality, blurry, altered product details, missing logo.

  INSTRUCTION:
  Return ONLY the generated image. Do not provide any text description, introduction, or chatter.
  `;

  if (feedback) {
    prompt += `\nUSER ADJUSTMENTS (IMPORTANT): ${feedback}`;
  }

  parts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image', // Using image model
      contents: { parts },
      config: {
         imageConfig: {
           aspectRatio: aspectRatio
         }
      }
    });

    if (response.candidates && response.candidates.length > 0) {
      const candidate = response.candidates[0];

      if (candidate.content && candidate.content.parts) {
        for (const part of candidate.content.parts) {
          if (part.inlineData && part.inlineData.data) {
            return `data:${part.inlineData.mimeType || 'image/png'};base64,${part.inlineData.data}`;
          }
        }
      }

      let textContent = "";
      if (candidate.content && candidate.content.parts) {
         for (const part of candidate.content.parts) {
             if (part.text) textContent += part.text;
         }
      }

      if (candidate.finishReason === 'SAFETY') {
          throw new Error("Hình ảnh bị chặn bởi bộ lọc an toàn (Safety Filter). Hãy thử ảnh hoặc mô tả khác.");
      }

      if (textContent) {
        console.warn("Model returned text instead of image:", textContent);
        throw new Error("AI không tạo ra hình ảnh mà chỉ trả về văn bản. Vui lòng thử lại hoặc điều chỉnh yêu cầu rõ ràng hơn.");
      }
    }

    throw new Error("Không tìm thấy dữ liệu ảnh trong phản hồi của AI.");
  } catch (error) {
    console.error("Error generating image:", error);
    throw error;
  }
};

