    if (!file.type.startsWith('image/')) {
        setError('Vui lòng chọn một file ảnh.');
        return;
    }

    try {
      setError(null);
      const processed = await processFile(file);
      setter(processed);
    } catch (err) {
      console.error(err);
      setError('Lỗi xử lý ảnh.');
    }
  };

