export const generateSpeech = async ({ text, voiceId, speed }: { text: string; voiceId: string; speed?: number; }): Promise<string> => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: { parts: [{ text: text }] },
            config: { 
              responseModalities: [Modality.AUDIO], 
              speechConfig: { 
                voiceConfig: { 
                  prebuiltVoiceConfig: { voiceName: voiceId } 
                } 
              } 
            }
        });
        const parts = response.candidates?.[0]?.content?.parts;
        if (parts) {
            for (const part of parts) { if (part.inlineData && part.inlineData.data) return part.inlineData.data; }
        }
        throw new Error("No audio generated");
    } catch (error) { throw error; }
};

export const decodeAudioData = async (base64String: string, audioContext: AudioContext): Promise<AudioBuffer> => {
  const binaryString = atob(base64String);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
  const sampleRate = 24000;
  const numChannels = 1;
  const dataInt16 = new Int16Array(bytes.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = audioContext.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
  }
  return buffer;
};

export const audioBufferToWav = (buffer: AudioBuffer): Blob => {
  const numOfChan = buffer.numberOfChannels;
  const length = buffer.length * numOfChan * 2 + 44;
  const bufferArr = new ArrayBuffer(length);
  const view = new DataView(bufferArr);
  let pos = 0;
  const setUint16 = (data: any) => { view.setUint16(pos, data, true); pos += 2; };
  const setUint32 = (data: any) => { view.setUint32(pos, data, true); pos += 4; };
  setUint32(0x46464952); setUint32(length - 8); setUint32(0x45564157);
  setUint32(0x20746d66); setUint32(16); setUint16(1); setUint16(numOfChan);
  setUint32(buffer.sampleRate); setUint32(buffer.sampleRate * 2 * numOfChan);
  setUint16(numOfChan * 2); setUint16(16); setUint32(0x61746164); setUint32(length - pos - 4);
  for(let i = 0; i < buffer.length; i++) {
    for(let channel = 0; channel < numOfChan; channel++) {
      let sample = Math.max(-1, Math.min(1, buffer.getChannelData(channel)[i]));
      view.setInt16(pos, (sample < 0 ? sample * 32768 : sample * 32767), true);
      pos += 2;
    }
  }
  return new Blob([bufferArr], {type: 'audio/wav'});
};

