import { GoogleGenAI, Modality } from "@google/genai";
import { GenerationRequest, ProcessedImage, ImageAsset, OptionItem } from '../types';

const API_KEY = process.env.API_KEY; 
const ai = new GoogleGenAI({ apiKey: API_KEY });

export const ensureApiKeySelected = async () => {
  return;
};

/**
 * Ghép người mẫu và sản phẩm - Cam kết giữ nguyên sản phẩm
 */
export const generateCompositeImage = async (request: GenerationRequest): Promise<string> => {
  const { personImage, productImage, customBackdrop, outfit, pose, backdrop, expression, aspectRatio, camera } = request;

  let backgroundInstruction = '';
  const parts: any[] = [];

  if (backdrop.id === 'custom_bg' && customBackdrop) {
      backgroundInstruction = `5. BACKGROUND: SỬ DỤNG HÌNH ẢNH 3 LÀM NỀN. Không thay đổi nội dung ảnh 3.`;
  } else if (backdrop.id === 'original_bg') {
      backgroundInstruction = `5. BACKGROUND: GIỮ NGUYÊN bối cảnh từ Ảnh 1.`;
  } else {
      backgroundInstruction = `5. BACKGROUND: Thay thế nền bằng: ${backdrop.prompt}. Ánh sáng phải khớp môi trường này.`;
  }

  const promptText = `
    ROLE: Chuyên gia Photoshop & AI Retouch thương mại.

    YÊU CẦU TỐI THƯỢNG (TUYỆT ĐỐI GIỮ NGUYÊN):
    1. SẢN PHẨM (ẢNH 2): GIỮ NGUYÊN 100%. KHÔNG thay đổi logo, KHÔNG thay đổi nhãn hiệu, KHÔNG vẽ lại bao bì, KHÔNG đổi màu sản phẩm. Sản phẩm trong kết quả phải là bản sao hoàn hảo của Ảnh 2.
    2. NGƯỜI MẪU (ẢNH 1): Giữ nguyên nhận diện gương mặt.
    3. TÍCH HỢP: Người mẫu cầm sản phẩm tự nhiên, ánh sáng và bóng đổ phải tự động khớp với bối cảnh mới một cách chân thực nhất.

    TASK: Ghép người mẫu (Ảnh 1) đang cầm sản phẩm (Ảnh 2) vào bối cảnh.

    ${expression.id === 'keep' ? 'Giữ biểu cảm Ảnh 1.' : `Đổi biểu cảm: "${expression.prompt}".`}
    2. TRANG PHỤC: ${outfit.id === 'keep' ? 'Giữ trang phục gốc.' : `Mặc: ${outfit.label}.`}
    3. TƯƠNG TÁC: Bàn tay cầm sản phẩm thật sự, có bóng đổ tiếp xúc.
    ${backgroundInstruction}
    ${camera && camera.id !== 'standard' ? `6. GÓC MÁY: ${camera.prompt}` : ''}

    CHẤT LƯỢNG: Siêu thực (Photorealistic), 8K, cinematic lighting.
  `;

  parts.push({ text: promptText });
  parts.push({ inlineData: { mimeType: personImage.mimeType, data: personImage.base64 } });
  parts.push({ inlineData: { mimeType: productImage.mimeType, data: productImage.base64 } });

  if (backdrop.id === 'custom_bg' && customBackdrop) {
      parts.push({ inlineData: { mimeType: customBackdrop.mimeType, data: customBackdrop.base64 } });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: parts },
      config: {
        responseModalities: ['IMAGE'],
        temperature: 0.1,
        imageConfig: { aspectRatio: aspectRatio.id }
      }
    });
    const partsRes = response.candidates?.[0]?.content?.parts;
    if (partsRes) {
        for (const part of partsRes) {
            if (part.inlineData && part.inlineData.data) return `data:image/png;base64,${part.inlineData.data}`;
        }
    }
    throw new Error("AI không tạo được ảnh.");
  } catch (error) { throw error; }
};

/**
 * Tạo ảnh Poster Quảng Cáo - Cam kết giữ nguyên sản phẩm
 */
export const generateAdImage = async (
    productImage: ProcessedImage, 
    logoImage: ProcessedImage | null, 
    customPrompt: string,
    aspectRatio: string = "1:1"
): Promise<string> => {
    const systemPrompt = `BẠN LÀ CHUYÊN GIA NHIẾP ẢNH QUẢNG CÁO (COMMERCIAL PHOTOGRAPHER).

    QUY TẮC BẤT DI BẤT DỊCH (PRODUCT INTEGRITY):
    1. GIỮ NGUYÊN SẢN PHẨM 100%: Tuyệt đối KHÔNG thay đổi bất kỳ chi tiết nào của sản phẩm trong ảnh nguồn. Nhãn mác, chữ viết, logo, nút bấm, nắp chai, hình dáng... PHẢI GIỮ NGUYÊN VẸN.
    2. CHỈ THAY ĐỔI BỐI CẢNH VÀ ÁNH SÁNG: AI chỉ được phép vẽ môi trường xung quanh sản phẩm và thêm ánh sáng (soft lighting, rim light, reflections) lên bề mặt sản phẩm để nó trông như được chụp thật trong môi trường đó.
    3. TÍCH HỢP TỰ NHIÊN: Sản phẩm phải có bóng đổ thực tế trên bề mặt bối cảnh mới.`;

    const parts: any[] = [];
    let baseQuery = `Tạo ảnh quảng cáo siêu thực cho sản phẩm này. Bối cảnh: ${customPrompt}. GIỮ NGUYÊN 100% CHI TIẾT SẢN PHẨM GỐC.`;

    parts.push({ inlineData: { mimeType: productImage.mimeType, data: productImage.base64 } });
    if (logoImage) {
        parts.push({ inlineData: { mimeType: logoImage.mimeType, data: logoImage.base64 } });
