import React, { useState, useCallback } from 'react';
import { 
  Sparkles, Download, RefreshCw, AlertCircle, 
  Box, User, Shirt, Hand, Layers, ImageIcon, Smile, Crop, Megaphone, PenTool, Mic, Lightbulb, Camera, BookOpen, Video, Wand2, Bolt, Eye, ScanEye, ChevronRight, Menu, X
} from 'lucide-react';

import { BACKDROPS, OUTFITS, POSES, EXPRESSIONS, ASPECT_RATIOS, CAMERA_ANGLES } from './constants';
import { ProcessedImage, OptionItem } from './types';
import { generateCompositeImage } from './services/geminiService';
import { ImageUploader } from './components/ImageUploader';
import { AIImageGenerator } from './components/AIImageGenerator';
import { TextToSpeech } from './components/TextToSpeech';
import { PromptBuilder } from './components/PromptBuilder';
import { VirtualTryOn } from './components/VirtualTryOn';
import { SoraPromptGen } from './components/SoraPromptGen';
import { HookGenerator } from './components/HookGenerator';
import { VisionScanner } from './components/VisionScanner';

const App: React.FC = () => {
  // Tabs update
  const [activeTab, setActiveTab] = useState<'studio' | 'ai_image_generator' | 'text_to_speech' | 'prompt_builder' | 'sora_prompt_gen' | 'hook_generator' | 'vision_scanner'>('studio');

  // Sidebar state
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Studio Sub-mode state
  const [studioMode, setStudioMode] = useState<'composite' | 'try_on'>('composite');

  // --- Fashion Studio (Composite) State ---
  const [personImage, setPersonImage] = useState<ProcessedImage | null>(null);
  const [productImage, setProductImage] = useState<ProcessedImage | null>(null);
  const [customBackdropImage, setCustomBackdropImage] = useState<ProcessedImage | null>(null);
  const [resultImage, setResultImage] = useState<string | null>(null);

  const [selectedOutfit, setSelectedOutfit] = useState<OptionItem>(OUTFITS[0]);
  const [selectedPose, setSelectedPose] = useState<OptionItem>(POSES[0]);
  const [selectedBackdrop, setSelectedBackdrop] = useState<OptionItem>(BACKDROPS[0]);
  const [selectedExpression, setSelectedExpression] = useState<OptionItem>(EXPRESSIONS[0]);
  const [selectedAspectRatio, setSelectedAspectRatio] = useState<OptionItem>(ASPECT_RATIOS[0]);
  const [selectedCamera, setSelectedCamera] = useState<OptionItem>(CAMERA_ANGLES[0]);

  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState('');
  const [statusMessage, setStatusMessage] = useState('');

  const processFile = (file: File): Promise<ProcessedImage> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        if (event.target?.result) {
            img.src = event.target.result as string;
            img.onload = () => {
              const canvas = document.createElement('canvas');
              const MAX_WIDTH = 1024; 
              const scaleSize = MAX_WIDTH / Math.max(img.width, MAX_WIDTH);
              canvas.width = img.width * scaleSize;
              canvas.height = img.height * scaleSize;
              const ctx = canvas.getContext('2d');
              if (ctx) {
                  ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
                  const dataUrl = canvas.toDataURL(file.type);
                  resolve({
                    preview: dataUrl,
                    base64: dataUrl.split(',')[1],
                    mimeType: file.type
                  });
              } else {
                  reject(new Error("Canvas context failed"));
              }
            };
            img.onerror = (e) => reject(e);
        }
      };
      reader.onerror = error => reject(error);
    });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, type: 'person' | 'product' | 'bg') => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      setError('');
      const processed = await processFile(file);
      if (type === 'person') {
        setPersonImage(processed);
      } else if (type === 'product') {
        setProductImage(processed);
      } else if (type === 'bg') {
        setCustomBackdropImage(processed);
      }
      setResultImage(null);
    } catch (err) {
      console.error(err);
      setError('Lỗi xử lý ảnh. Vui lòng thử file khác.');
    }
  };

  const handleGenerate = async () => {
    if (!personImage || !productImage) {
      setError('Vui lòng tải lên cả ảnh người mẫu và ảnh sản phẩm.');
      return;
    }

    if (selectedBackdrop.id === 'custom_bg' && !customBackdropImage) {
        setError('Vui lòng tải lên ảnh nền tùy chọn hoặc chọn bối cảnh có sẵn.');
        return;
    }

    setIsGenerating(true);
    setError('');
    setResultImage(null);
    setStatusMessage('Đang phân tích...');

    try {
      setTimeout(() => setStatusMessage('Đang xử lý ảnh...'), 2000);

      const result = await generateCompositeImage({
          personImage,
          productImage,
          customBackdrop: selectedBackdrop.id === 'custom_bg' ? customBackdropImage : null,
          outfit: selectedOutfit,
          pose: selectedPose,
          backdrop: selectedBackdrop,
          expression: selectedExpression,
          aspectRatio: selectedAspectRatio,
          camera: selectedCamera
      });

      setResultImage(result);
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'Tạo ảnh thất bại. Vui lòng thử lại.');
    } finally {
      setIsGenerating(false);
      setStatusMessage('');
    }
  };

  const handleReset = () => {
    setPersonImage(null);
    setProductImage(null);
    setCustomBackdropImage(null);
    setResultImage(null);
    setError('');
    setSelectedOutfit(OUTFITS[0]);
    setSelectedPose(POSES[0]);
    setSelectedBackdrop(BACKDROPS[0]);
    setSelectedExpression(EXPRESSIONS[0]);
    setSelectedAspectRatio(ASPECT_RATIOS[0]);
    setSelectedCamera(CAMERA_ANGLES[0]);
  };

  const downloadImage = () => {
    if (resultImage) {
      const link = document.createElement('a');
      link.href = resultImage;
      link.download = `studio-gen-${selectedBackdrop.id}-${Date.now()}.png`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  const menuItems = [
    { id: 'studio', label: 'Fashion Studio', icon: Shirt, desc: 'Ghép mặt & Thử đồ ảo' },
