                    <div className="p-2 border-t border-slate-100 bg-slate-50 text-[10px] text-right text-slate-400 font-mono">
                        {generatedContent.length} ký tự
                    </div>
                )}
            </div>
        </div>
      </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";

// Initialize AI directly with the provided API key
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export interface AIScriptScene {
  time: string;
  section: string;
  visual: string;
  audio: string;
}

export interface AIScript {
  title: string;
  scenes: AIScriptScene[];
  isSafe: boolean;
}

export interface AIHookResult {
  category: string;
  hook: string;
}

// Global Policy Instructions for the AI
const POLICY_INSTRUCTIONS = `
TUYÊN THỦ NGHIÊM NGẶT LUẬT POLICY & TIÊU CHUẨN CỘNG ĐỒNG:
1. KHÔNG sử dụng các từ tuyệt đối hóa: "trị dứt điểm", "chữa khỏi", "cam kết 100%", "vĩnh viễn", "tuyệt đối", "100%", "chắc chắn hết".
2. KHÔNG sử dụng từ liên quan đến y tế/thuốc: "thuốc", "điều trị", "bệnh viện", "bác sĩ" (thay bằng "sản phẩm", "hỗ trợ", "chuyên gia", "nơi uy tín").
3. KHÔNG sử dụng từ ngữ gây chia rẽ: "giàu", "nghèo", "sang", "hèn", "vô học", "nhà giàu" (thay bằng "người có điều kiện", "tiết kiệm", "phù hợp hoàn cảnh").
4. KHÔNG so sánh tiêu cực/dìm đối thủ: Không chê bai sản phẩm khác, không dùng từ "dỏm", "lởm", "đểu".
5. KHÔNG sử dụng từ nhạy cảm dễ bị bóp tương tác: Hạn chế "giá", "tiền", "mua", "bán", "chốt đơn" trực tiếp trong 3s đầu.
6. TUÂN THỦ 10 QUY ĐỊNH NỀN TẢNG: Không chính trị, không tôn giáo, không bạo lực, không hứa hẹn phi thực tế.
7. GIỌNG VĂN: Luôn tự nhiên, thân thiện như người thật chia sẻ, không máy móc quảng cáo.
`;

/**
 * Generates a full viral video script based on product details and duration.
 */
export const generateAdvancedScript = async (
  productName: string, 
  solution: string, 
  scriptType: string,
  region: string,
  duration: number // New duration parameter in seconds
): Promise<AIScript> => {
  const prompt = `Bạn là một chuyên gia sáng tạo nội dung hàng đầu cho TikTok và Facebook Affiliate tại Việt Nam. 
  Hãy viết một kịch bản video viral cho sản phẩm: "${productName}" với điểm mạnh: "${solution}".
  Loại kịch bản: ${scriptType}.
  Giọng văn: ${region === 'north' ? 'Miền Bắc' : region === 'south' ? 'Miền Nam' : region === 'central' ? 'Miền Trung' : 'Phổ thông'}.
  Thời lượng mục tiêu: ${duration} giây.

  ${POLICY_INSTRUCTIONS}

  Yêu cầu CHẶT CHẼ về cấu trúc kịch bản dài ${duration}s:
  - Chia kịch bản thành các cảnh (scenes) chi tiết để đảm bảo tổng thời lượng đạt ${duration} giây.
  - HOOK (3-5s đầu): Phải cực kỳ thu hút nhưng không chứa từ cấm.
  - AGITATE/BODY: Phát triển sâu về vấn đề và trải nghiệm sử dụng. Với thời lượng dài, hãy thêm các tình huống thực tế (storytelling).
  - SOLUTION & DETAILS: Giới thiệu sản phẩm và phân tích sâu các tính năng/lợi ích.
  - PROOF/DEMO: Mô tả kỹ các phân cảnh test sản phẩm, so sánh trước/sau hoặc cảm nhận chi tiết.
  - CTA: Kêu gọi hành động tinh tế và nhắc lại ưu đãi.

  Trả về JSON chuẩn format:
  {
    "title": "Tên kịch bản hấp dẫn (Đã chuẩn Policy)",
    "scenes": [
      {"time": "0:00 - 0:05", "section": "HOOK", "visual": "mô tả hình ảnh chi tiết", "audio": "lời thoại tự nhiên"},
      ...
    ],
    "isSafe": true
  }`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          scenes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                time: { type: Type.STRING },
                section: { type: Type.STRING },
                visual: { type: Type.STRING },
                audio: { type: Type.STRING }
              },
              required: ["time", "section", "visual", "audio"]
            }
          },
          isSafe: { type: Type.BOOLEAN }
        },
        required: ["title", "scenes", "isSafe"]
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

