/**
 * Analyzes a given script for policy violations and suggests fixes.
 */
export const analyzeScriptWithAI = async (text: string) => {
  const prompt = `Phân tích kịch bản sau để tìm các lỗi vi phạm chính sách của TikTok/Facebook Ads và các tiêu chuẩn cộng đồng mới nhất:
  "${text}"

  Yêu cầu:
  1. Kiểm tra từ khóa bị cấm: trị dứt điểm, cam kết, thuốc, bác sĩ, 100%, tốt nhất...
  2. Kiểm tra từ khóa bị bóp tương tác: giá, tiền, mua, bán, zalo, link...
