import { GoogleGenAI, Type } from "@google/genai";

// Initialize AI directly with the provided API key
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export interface AIScriptScene {
  time: string;
  section: string;
  visual: string;
  audio: string;
}

export interface AIScript {
