// Global Policy Instructions for the AI
const POLICY_INSTRUCTIONS = `
TUYÊN THỦ NGHIÊM NGẶT LUẬT POLICY & TIÊU CHUẨN CỘNG ĐỒNG:
1. KHÔNG sử dụng các từ tuyệt đối hóa: "trị dứt điểm", "chữa khỏi", "cam kết 100%", "vĩnh viễn", "tuyệt đối", "100%", "chắc chắn hết".
2. KHÔNG sử dụng từ liên quan đến y tế/thuốc: "thuốc", "điều trị", "bệnh viện", "bác sĩ" (thay bằng "sản phẩm", "hỗ trợ", "chuyên gia", "nơi uy tín").
3. KHÔNG sử dụng từ ngữ gây chia rẽ: "giàu", "nghèo", "sang", "hèn", "vô học", "nhà giàu" (thay bằng "người có điều kiện", "tiết kiệm", "phù hợp hoàn cảnh").
4. KHÔNG so sánh tiêu cực/dìm đối thủ: Không chê bai sản phẩm khác, không dùng từ "dỏm", "lởm", "đểu".
5. KHÔNG sử dụng từ nhạy cảm dễ bị bóp tương tác: Hạn chế "giá", "tiền", "mua", "bán", "chốt đơn" trực tiếp trong 3s đầu.
6. TUÂN THỦ 10 QUY ĐỊNH NỀN TẢNG: Không chính trị, không tôn giáo, không bạo lực, không hứa hẹn phi thực tế.
7. GIỌNG VĂN: Luôn tự nhiên, thân thiện như người thật chia sẻ, không máy móc quảng cáo.
`;

/**
 * Transforms an existing script into a new, policy-safe version.
 */
export const rewriteScriptWithAI = async (
  originalScript: string,
  region: string,
  duration: number
): Promise<AIScript> => {
  const prompt = `Bạn là một chuyên gia sáng tạo nội dung kịch bản video. 
  NHIỆM VỤ: Chuyển đổi kịch bản gốc sau đây thành một kịch bản MỚI, hấp dẫn hơn và TUYỆT ĐỐI TUÂN THỦ CHÍNH SÁCH.

  Kịch bản gốc: "${originalScript}"
  Giọng văn: ${region === 'north' ? 'Miền Bắc' : region === 'south' ? 'Miền Nam' : region === 'central' ? 'Miền Trung' : 'Phổ thông'}.
  Thời lượng mục tiêu: ${duration} giây.

  ${POLICY_INSTRUCTIONS}

  YÊU CẦU:
  1. Phân tích kịch bản gốc để giữ lại ý tưởng/cốt truyện chính.
  2. Viết lại hoàn toàn lời thoại: Lách tất cả các từ cấm, từ nhạy cảm bằng cách dùng từ đồng nghĩa tinh tế (VD: "thuốc" -> "em này", "trị dứt điểm" -> "hỗ trợ cải thiện rõ rệt").
  3. Cấu trúc lại các phân cảnh để phù hợp với thời lượng ${duration}s.
  4. Đảm bảo 3s đầu (Hook) cực kỳ cuốn hút nhưng "sạch" chính sách.

  Trả về JSON chuẩn format:
  {
    "title": "Kịch bản chuyển đổi - An toàn Reach",
    "scenes": [
      {"time": "0:00 - 0:05", "section": "HOOK", "visual": "mô tả hình ảnh mới", "audio": "lời thoại mới an toàn"},
      ...
    ],
    "isSafe": true
  }`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          scenes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                time: { type: Type.STRING },
                section: { type: Type.STRING },
                visual: { type: Type.STRING },
                audio: { type: Type.STRING }
              },
              required: ["time", "section", "visual", "audio"]
            }
          },
          isSafe: { type: Type.BOOLEAN }
        },
        required: ["title", "scenes", "isSafe"]
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

