    holiday: { hooks: [{ t: "[Wow]! Món quà này đảm bảo ai cũng thích.", v: "Cầm hộp quà." }], agitates: [{ t: "Sắp đến lễ rồi mà chưa biết tặng gì?", v: "Xem lịch." }], solutions: [{ t: "Em [Product] này vừa đẹp vừa [Solution].", v: "Quay sản phẩm." }], proofs: [{ t: "Tặng xong là được cưng xỉu.", v: "Hình vui vẻ." }], ctas: [{ t: "Săn ngay kẻo hết, [Urgent]!", v: "Chỉ giỏ hàng." }] },
    sale: { hooks: [{ t: "[Wow]! Giá sốc chưa từng có chỉ trong hôm nay!", v: "Biểu cảm sốc." }], agitates: [{ t: "Bình thường giá cao, nay giảm sâu quá trời.", v: "So sánh giá." }], solutions: [{ t: "Cơ hội rinh [Product] để có [Solution].", v: "Sản phẩm." }], proofs: [{ t: "Số lượng có hạn, hốt lẹ nha!", v: "Thanh số lượng." }], ctas: [{ t: "[Urgent] ngay kẻo hết mã giảm giá!", v: "Bấm giỏ hàng." }] },
    review: { hooks: [{ t: "Review chân thật [Product] không nhận quảng cáo nha.", v: "Mặt nghiêm túc." }], agitates: [{ t: "Thấy quảng cáo rầm rộ nên mua về test thử.", v: "Mở hộp." }], solutions: [{ t: "Cảm nhận là [Solution], khá là [Adj_Pos].", v: "Dùng thử." }], proofs: [{ t: "Tuy nhiên điểm trừ là... nhưng giá này quá ổn.", v: "Soi chi tiết." }], ctas: [{ t: "Đáng tiền, [Urgent] nhé.", v: "Thả tim." }] },
    experience: { hooks: [{ t: "Một ngày của tui thay đổi thế nào nhờ [Product]?", v: "Vlog." }], agitates: [{ t: "Hồi trước làm cái này cực lắm.", v: "Cảnh bận rộn." }], solutions: [{ t: "Nhờ em [Product] này giúp [Solution].", v: "Dùng sản phẩm." }], proofs: [{ t: "Đi đâu cũng phải mang theo.", v: "Bỏ túi." }], ctas: [{ t: "Link ở phần tiểu sử nha.", v: "Chỉ vào profile." }] },
    story: { hooks: [{ t: "Câu chuyện thay đổi của tui nhờ [Product]?", v: "Ảnh ngày xưa." }], agitates: [{ t: "Từng rất tự ti vì vấn đề này.", v: "Mặt buồn." }], solutions: [{ t: "Biết đến [Product], nó giúp [Solution].", v: "Thay đổi." }], proofs: [{ t: "Giờ tự tin hơn hẳn.", v: "Cười tươi." }], ctas: [{ t: "Thử ngay đi nhé.", v: "Cổ vũ." }] },
    asmr: { hooks: [{ t: "(Tiếng gõ)... Khui hộp [Product] nha.", v: "Gõ hộp." }], agitates: [{ t: "Nghe tiếng này là thấy [Adj_Pos] rồi.", v: "Xé bao bì." }], solutions: [{ t: "Chất lượng xịn xò, giúp [Solution].", v: "Cận cảnh." }], proofs: [{ t: "Nhìn cận cảnh nè...", v: "Góc quay macro." }], ctas: [{ t: "Link bên dưới nha... suỵt...", v: "Vẫy tay." }] }
  };

  const applyDialect = (text: string, region: string) => {
    if (!text) return "";
    let converted = text;
    if (region === 'north') converted = converted.replace(/mấy bà/gi, "các bác").replace(/tui/gi, "em").replace(/nha/gi, "nhá").replace(/hông/gi, "không");
    else if (region === 'central') converted = converted.replace(/mấy bà/gi, "mấy o").replace(/tôi/gi, "tui").replace(/nha/gi, "hỉ");
    else if (region === 'south') converted = converted.replace(/không/gi, "hông").replace(/nhế/gi, "nha");
    return converted;
  };

  const getSectionTemplate = (type: string, sectionName: string) => {
    const library = scriptLibrary[type] || scriptLibrary['intro']; 
    let section = library[sectionName.toLowerCase()] || library[sectionName];
    if (!section && type === 'usage') {
        if (sectionName.includes('STEP')) section = library['steps'];
        else if (sectionName === 'TIPS') section = library['tips'];
    }
    if (!section) {
        if (sectionName === 'HOOK') section = library['hooks'];
        else if (sectionName === 'AGITATE') section = library['agitates'];
        else if (sectionName === 'SOLUTION') section = library['solutions'];
        else if (sectionName === 'PROOF') section = library['proofs'];
        else if (sectionName === 'DETAIL') section = library['details'] || library['proofs'];
        else section = library['ctas'];
    }
    return section[Math.floor(Math.random() * section.length)] || { t: "...", v: "..." };
  };

  const generateScript = () => {
    if (!productName || !solution) return;
    const cleanProduct = sanitizeText(productName);
    const cleanSolution = sanitizeText(solution);

    const createScene = (st: string, time: string) => {
        let template = getSectionTemplate(scriptType, st);
        let audio = applyDialect(fillTemplate(template.t.replace(/\[Product\]/g, cleanProduct).replace(/\[Solution\]/g, cleanSolution)), region);
        return { time, section: st, visual: template.v, audio };
    };

    let scenes = [];
    if (duration <= 30) {
      scenes = [createScene('HOOK', "0:00"), createScene('AGITATE', "0:05"), createScene('SOLUTION', "0:15"), createScene('PROOF', "0:22"), createScene('CTA', "0:27")];
    } else if (duration <= 60) {
      scenes = [createScene('HOOK', "0:00"), createScene('AGITATE', "0:05"), createScene('DETAIL', "0:15"), createScene('SOLUTION', "0:25"), createScene('PROOF', "0:40"), createScene('CTA', "0:55")];
    } else {
      // 90s - 120s
      scenes = [
        createScene('HOOK', "0:00"), 
        createScene('AGITATE', "0:05"), 
        createScene('DETAIL 1', "0:20"), 
        createScene('DETAIL 2', "0:35"), 
        createScene('SOLUTION', "0:50"), 
        createScene('PROOF 1', "1:05"), 
        createScene('PROOF 2', "1:30"), 
        createScene('CTA', "1:50")
      ];
    }

    setScript({ title: `Kịch bản ${scriptTypeLabels[scriptType]} - ${duration}s`, scenes, isSafe: true });
    showToast(`Đã tạo kịch bản ngẫu nhiên ${duration}s!`);
  };

  const handleGenerateAIScript = async () => {
    if (!productName || !solution) return;
    setIsAIProcessing(true);
    try {
      const aiScript = await generateAdvancedScript(sanitizeText(productName), sanitizeText(solution), scriptType, region, duration);
      setScript(aiScript);
      showToast(`Đã tạo kịch bản AI ${duration}s!`);
    } catch (error) { 
      showToast("Lỗi AI. Đang sử dụng mẫu ngẫu nhiên."); 
      generateScript(); 
    } finally { 
      setIsAIProcessing(false); 
    }
  };

  const handleCopyResult = () => {
    if (!script) return;
    const text = script.scenes.map((s: any) => `[${s.time}] ${s.section}\n- Hình ảnh: ${s.visual}\n- Lời thoại: ${s.audio}`).join('\n\n');
    copyToClipboard(text, () => {
      setIsCopied(true);
      showToast("Đã sao chép kịch bản!");
      setTimeout(() => setIsCopied(false), 2000);
    });
  };

  const handleCopyVoice = () => {
    if (!script) return;
    const text = script.scenes.map((s: any) => s.audio).join(' ');
    copyToClipboard(text, () => {
      setIsVoiceCopied(true);
      showToast("Đã sao chép lời thoại!");
      setTimeout(() => setIsVoiceCopied(false), 2000);
    });
  };

  const scriptTypeLabels: Record<string, string> = {
    intro: 'Quảng Cáo',
    usage: 'Hướng dẫn',
    holiday: 'Ngày Lễ - Tết',
    sale: 'Giảm giá',
    review: 'Đánh giá',
    experience: 'Trải nghiệm',
    story: 'Kể chuyện',
    asmr: 'ASMR/UNBOX'
  };

  const regionLabels: Record<string, string> = {
    standard: 'Phổ thông',
    north: 'Miền Bắc',
    central: 'Miền Trung',
    south: 'Miền Nam'
  };

  const durations = [30, 60, 90, 120];

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="space-y-4">
          <h2 className="text-lg font-bold text-slate-800 flex justify-between">Thông tin <span className="text-xs bg-indigo-100 text-indigo-700 px-2 py-1 rounded-full flex items-center border border-indigo-200"><Lock size={12} className="mr-1"/> Chế độ an toàn</span></h2>

          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-500 uppercase flex items-center gap-1"><Clock size={12}/> Thời lượng video</label>
            <div className="grid grid-cols-4 gap-2">
              {durations.map(d => (
                <button key={d} onClick={() => setDuration(d)} className={`py-2 text-[11px] font-bold border rounded-lg transition ${duration === d ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-slate-300 text-slate-600 hover:bg-slate-50'}`}>{d}s</button>
              ))}
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-500 uppercase">Loại kịch bản</label>
            <div className="grid grid-cols-4 gap-2">
              {Object.keys(scriptTypeLabels).map(t => (
                <button key={t} onClick={() => setScriptType(t)} className={`py-2 text-[11px] font-medium border rounded-lg transition ${scriptType === t ? 'bg-indigo-50 border-indigo-500 text-indigo-700' : 'bg-white border-slate-300 text-slate-600'}`}>{scriptTypeLabels[t]}</button>
              ))}
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-500 uppercase">Giọng văn vùng miền</label>
            <div className="grid grid-cols-4 gap-2">
              {Object.keys(regionLabels).map(r => (
                 <button key={r} onClick={() => setRegion(r)} className={`py-1 text-xs border rounded ${region === r ? 'bg-indigo-600 text-white' : 'bg-white border-slate-300'}`}>{regionLabels[r]}</button>
              ))}
            </div>
          </div>

          <input className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-sm" placeholder="Tên sản phẩm..." value={productName} onChange={e => setProductName(e.target.value)} />
          <textarea className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-sm" placeholder="Điểm mạnh sản phẩm (USP)..." rows={3} value={solution} onChange={e => setSolution(e.target.value)} />

          <div className="flex gap-2">
            <button onClick={generateScript} className="flex-1 bg-white border-2 border-slate-200 font-semibold py-3 rounded-lg text-sm transition hover:bg-slate-50"><Shuffle size={18} className="inline mr-1"/> Ngẫu nhiên</button>
            <button onClick={handleGenerateAIScript} disabled={isAIProcessing} className="flex-[2] bg-indigo-600 text-white font-semibold py-3 rounded-lg shadow-md flex items-center justify-center text-sm hover:bg-indigo-700 transition active:scale-95">
              {isAIProcessing ? <RefreshCw className="animate-spin mr-2" /> : <BrainCircuit size={18} className="mr-2" />} Tạo kịch bản AI
            </button>
          </div>
        </div>

        <div className="bg-slate-50 p-4 rounded-xl border flex flex-col min-h-[400px]">
          <h2 className="text-lg font-bold mb-4 flex items-center justify-between">
            Kịch bản chi tiết
            {script?.isSafe && <span className="text-[10px] bg-green-100 text-green-700 px-2 py-0.5 rounded font-bold border border-green-200 uppercase">Chuẩn Policy</span>}
          </h2>
          {!script ? <div className="flex-1 flex flex-col items-center justify-center text-slate-400 opacity-50"><Film size={48} /><p className="text-sm mt-2">Điền thông tin và chọn thời lượng</p></div> : (
            <div className="space-y-4 animate-fadeIn overflow-y-auto pr-2 custom-scrollbar">
               <div className="flex justify-between items-center pb-2 border-b">
                 <div className="flex flex-col">
                    <h3 className="font-bold text-indigo-700 truncate text-sm">{script.title}</h3>
                    <span className="text-[10px] text-slate-400 font-bold uppercase">{duration} giây • {script.scenes.length} phân cảnh</span>
                 </div>
                 <div className="flex gap-2">
                   <button onClick={() => setShowVoiceModal(true)} className="bg-indigo-600 text-white p-1.5 rounded hover:bg-indigo-700" title="Trích xuất lời thoại"><Mic size={14}/></button>
                   <button 
                    onClick={handleCopyResult} 
                    className={`p-1.5 rounded border transition-colors ${isCopied ? 'bg-green-600 border-green-600 text-white' : 'bg-white text-slate-600 hover:bg-slate-100'}`}
                    title="Sao chép kịch bản"
                   >
                     {isCopied ? <Check size={14} /> : <Copy size={14}/>}
                   </button>
                 </div>
               </div>
               {script.scenes.map((s:any, i:number) => (
                 <div key={i} className="bg-white p-3 rounded-lg border shadow-sm hover:border-indigo-200 transition">
                   <div className="flex justify-between text-[10px] font-semibold text-slate-500 mb-1.5">
                     <span className="bg-slate-100 px-2 py-0.5 rounded">{s.section}</span>
                     <span className="flex items-center gap-1"><Clock size={10}/> {s.time}</span>
                   </div>
                   <div className="text-xs text-slate-600 italic leading-relaxed border-l-2 border-slate-200 pl-2 mb-2">{s.visual}</div>
                   <div className="text-sm font-medium text-slate-800 bg-indigo-50/50 p-2 rounded border border-indigo-100/50">"{s.audio}"</div>
                 </div>
               ))}
            </div>
          )}
        </div>
      </div>
      {showVoiceModal && script && (
        <div className="fixed inset-0 bg-black/60 z-[150] flex items-center justify-center p-4 backdrop-blur-sm animate-fadeIn">
          <div className="bg-white rounded-xl shadow-2xl max-w-lg w-full max-h-[80vh] flex flex-col">
            <div className="p-4 border-b flex justify-between items-center bg-indigo-50 font-bold">
              <span className="flex items-center text-sm text-indigo-800"><Mic size={18} className="mr-2 text-indigo-600"/> Lời thoại video ({duration}s)</span>
              <button onClick={() => setShowVoiceModal(false)} className="hover:text-red-600 transition"><X size={20}/></button>
            </div>
            <div className="p-6 overflow-y-auto text-base leading-loose text-slate-700 font-normal whitespace-pre-wrap">{script.scenes.map((s:any)=>`[${s.time}] ${s.audio}`).join('\n\n')}</div>
            <div className="p-4 border-t flex justify-end bg-slate-50">
              <button 
                onClick={handleCopyVoice} 
                className={`px-4 py-2 rounded-lg font-semibold transition-all flex items-center shadow-md text-sm active:scale-95 ${isVoiceCopied ? 'bg-green-600 text-white' : 'bg-indigo-600 text-white hover:bg-indigo-700'}`}
              >
                {isVoiceCopied ? <><Check size={18} className="mr-1"/> Đã sao chép</> : <><Copy size={16} className="mr-2"/> Sao chép lời thoại</>}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const HookLibrary: React.FC<{ showToast: (msg: string) => void }> = ({ showToast }) => {
  const [productInput, setProductInput] = useState('');
  const [productDetails, setProductDetails] = useState('');
  const [hooks, setHooks] = useState<AIHookResult[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingScript, setIsGeneratingScript] = useState(false);
  const [viewScript, setViewScript] = useState<AIScript | null>(null);
  const [showVoiceModal, setShowVoiceModal] = useState(false);
  const [category, setCategory] = useState('all');

  const [isScriptCopied, setIsScriptCopied] = useState(false);
  const [isVoiceCopied, setIsVoiceCopied] = useState(false);

  const localHooks: any = {
    curiosity: ["Sự thật về [Product] ít người biết...", "Cân nhắc kỹ trước khi mua [Product]!", "Bất ngờ khi biết đến [Product] sớm..."],
    pain: ["Cách giải quyết vấn đề với [Product].", "Nếu gặp khó khăn, [Product] là gợi ý.", "Lý do nên tham khảo [Product]."],
    trend: ["Thấy mọi người nhắc [Product] nhiều quá...", "Đập hộp [Product] đang cực hot.", "Thử [Product] xem có như lời đồn?"],
    comparison: ["So sánh [Product] với giải pháp thông thường.", "Tại sao [Product] lại vượt trội hơn các loại khác?"],
    feedback: ["Khách hàng nói gì sau khi dùng [Product]?", "Cùng xem trải nghiệm thực tế với [Product]."],
    knowledge: ["Mẹo hay khi sử dụng [Product].", "Bí quyết tận dụng tối đa công năng của [Product]."]
  };

  const generate = async (isAI: boolean) => {
    if (!productInput) return;
    if (isAI) {
      setIsGenerating(true);
      try { 
        const result = await generateAIHooks(sanitizeText(productInput), sanitizeText(productDetails));
        setHooks(result); 
        showToast("Đã tạo 12 Hook (Đã xác minh chính sách)!"); 
        setCategory('all');
      } catch { generate(false); }
      finally { setIsGenerating(false); }
    } else {
      const p = sanitizeText(productInput);
      const all: AIHookResult[] = [];
      Object.keys(localHooks).forEach(cat => {
        localHooks[cat].forEach((h: string) => {
          all.push({ category: cat, hook: h.replace(/\[Product\]/g, p) });
        });
      });
      setHooks(all.sort(() => 0.5 - Math.random()));
      showToast("Đã tải các mẫu có sẵn!");
    }
  };

  const handleGenerateScriptFromHook = async (hook: string) => {
    if (!productInput) return;
    setIsGeneratingScript(true);
    try {
      const script = await generateScriptFromHook(hook, sanitizeText(productInput), sanitizeText(productDetails));
      setViewScript(script);
      showToast("Đã tạo kịch bản review (Chế độ an toàn)!");
    } catch (error) {
      showToast("Lỗi khi tạo kịch bản AI.");
    } finally {
      setIsGeneratingScript(false);
    }
  };

  const getVoiceOnlyText = () => {
    if (!viewScript) return "";
    return viewScript.scenes.map(s => `[${s.time}] ${s.audio}`).join('\n\n');
  };

  const filteredHooks = category === 'all' ? hooks : hooks.filter(h => h.category.toLowerCase().includes(category.toLowerCase()));

  const categoryLabels: any = {
    all: 'Tất cả',
    curiosity: 'Gây tò mò',
    pain: 'Nỗi đau',
    trend: 'Bắt trend',
    comparison: 'So sánh',
    feedback: 'Phản hồi',
    knowledge: 'Kiến thức'
  };

  return (
    <div className="space-y-6">
      <div className="bg-indigo-50 p-6 rounded-xl border border-indigo-100 space-y-4">
        <div className="flex justify-between items-center">
          <h2 className="text-lg font-bold flex items-center"><Zap className="mr-2 text-yellow-500" /> Tạo tiêu đề (Hook)</h2>
          <span className="text-[10px] bg-indigo-600 text-white px-2 py-1 rounded font-bold flex items-center"><ShieldCheck size={10} className="mr-1"/> Tuân thủ chính sách</span>
        </div>
        <div className="space-y-3">
            <input 
              className="w-full p-3 border rounded-lg outline-none focus:ring-2 focus:ring-indigo-500 transition-all font-normal text-sm" 
              placeholder="Tên sản phẩm (VD: Máy hút bụi cầm tay)..." 
              value={productInput} 
              onChange={e => setProductInput(e.target.value)} 
            />
            <textarea 
              className="w-full p-3 border rounded-lg outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm" 
              placeholder="Điểm mạnh / USP (VD: Lực hút mạnh, pin trâu 60p, thiết kế nhẹ)..." 
              value={productDetails} 
              onChange={e => setProductDetails(e.target.value)} 
              rows={2}
            />
        </div>
        <div className="flex gap-2">
          <button onClick={() => generate(false)} className="flex-1 bg-white border-2 border-indigo-600 text-indigo-600 font-semibold py-3 rounded-lg hover:bg-indigo-50 transition text-sm">Dùng mẫu sẵn</button>
          <button onClick={() => generate(true)} disabled={isGenerating || !productInput} className="flex-[2] bg-indigo-600 text-white font-semibold py-3 rounded-lg flex justify-center items-center shadow-md hover:bg-indigo-700 transition disabled:opacity-50 text-sm">
            {isGenerating ? <RefreshCw className="animate-spin mr-2" /> : <Sparkles className="mr-2"/>} TẠO TIÊU ĐỀ HOOK
          </button>
        </div>
      </div>

      {hooks.length > 0 && (
        <div className="flex flex-wrap gap-2 py-2 border-b border-slate-100 overflow-x-auto whitespace-nowrap custom-scrollbar">
          {Object.entries(categoryLabels).map(([id, label]: [string, any]) => (
            <button 
              key={id} 
              onClick={() => setCategory(id)}
              className={`px-4 py-1.5 rounded-full text-xs font-medium border transition-all ${category === id ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-slate-200 text-slate-500 hover:border-indigo-300'}`}
            >
              {label}
            </button>
          ))}
        </div>
      )}

      {isGeneratingScript && (
        <div className="fixed inset-0 bg-black/20 z-[110] flex items-center justify-center backdrop-blur-sm">
          <div className="bg-white p-6 rounded-xl shadow-xl flex flex-col items-center animate-bounce">
            <BrainCircuit className="h-10 w-10 text-indigo-600 animate-pulse" />
            <p className="mt-2 font-semibold text-indigo-900 text-sm">Đang viết kịch bản</p>
          </div>
        </div>
      )}

      <div className="grid gap-4">
        {hooks.length === 0 ? (
          <div className="text-center py-12 bg-slate-50/50 rounded-xl border border-dashed border-slate-200">
            <Layers className="mx-auto mb-3 opacity-10" size={64} />
            <p className="text-slate-400 font-medium italic text-sm">Nhập tên sản phẩm!</p>
          </div>
        ) : (
          filteredHooks.map((h, i) => (
            <div key={i} className="bg-white p-4 rounded-xl border border-slate-200 hover:border-indigo-400 flex justify-between items-center group transition-all hover:shadow-lg animate-fadeIn relative">
              <div className="flex-1 pr-4">
                <div className="flex items-center gap-2 mb-1.5">
                  <span className="text-[10px] font-semibold bg-indigo-50 text-indigo-600 px-2 py-0.5 rounded border border-indigo-100">
                    {categoryLabels[h.category] || h.category}
                  </span>
                  <span className="text-indigo-400 font-medium text-[10px]">#0{i+1}</span>
                </div>
