3. KHÔNG sử dụng từ ngữ gây chia rẽ: "giàu", "nghèo", "sang", "hèn", "vô học", "nhà giàu" (thay bằng "người có điều kiện", "tiết kiệm", "phù hợp hoàn cảnh").
4. KHÔNG so sánh tiêu cực/dìm đối thủ: Không chê bai sản phẩm khác, không dùng từ "dỏm", "lởm", "đểu".
5. KHÔNG sử dụng từ nhạy cảm dễ bị bóp tương tác: Hạn chế "giá", "tiền", "mua", "bán", "chốt đơn" trực tiếp trong 3s đầu.
6. TUÂN THỦ 10 QUY ĐỊNH NỀN TẢNG: Không chính trị, không tôn giáo, không bạo lực, không hứa hẹn phi thực tế.
7. GIỌNG VĂN: Luôn tự nhiên, thân thiện như người thật chia sẻ.
8. TRÁNH LẶP TỪ: Sử dụng vốn từ phong phú, không lặp lại cùng một từ ngữ hoặc cấu trúc câu quá 2 lần trong một kịch bản. Sử dụng từ đồng nghĩa linh hoạt.
`;

const getRegionInstruction = (region: string) => {
  const regions: Record<string, string> = {
    standard: "Tiếng Việt phổ thông, chuẩn mực.",
    hanoi: "Giọng Hà Nội gốc, lịch sự, dùng từ ngữ tinh tế của người thủ đô.",
    saigon: "Giọng Sài Gòn hiện đại, năng động, dùng các từ như 'hông', 'nè', 'nha'.",
    mientay: "Giọng Miền Tây (Cần Thơ/Long An), dùng từ dân dã, chân chất như 'tui', 'thiệt tình', 'hết sảy'.",
    hue: "Giọng Huế (Thừa Thiên Huế), nhẹ nhàng, dùng từ địa phương như 'tê', 'mô', 'răng', 'rứa'.",
    nghetinh: "Giọng Nghệ Tĩnh (Nghệ An/Hà Tĩnh), dùng từ mộc mạc, mạnh mẽ như 'choa', 'nỏ', 'mần'.",
    haiphong: "Giọng Hải Phòng, bộc trực, mạnh mẽ, dùng từ ngữ cá tính, đời thường.",
    danang: "Giọng Đà Nẵng/Quảng Nam, trung tính nhưng có âm sắc đặc trưng, dùng từ như 'ni', 'tê'."
  };
  return regions[region] || regions.standard;
};

