          {rewrittenScript && <span className="text-[10px] bg-green-100 text-green-700 px-3 py-1 rounded-full font-bold border border-green-200 flex items-center gap-1"><ShieldCheck size={12}/> AN TOÀN REACH</span>}
        </h2>

        {!rewrittenScript ? (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-300 opacity-50">
            <Repeat size={64} />
            <p className="mt-4 text-sm font-medium">Kết quả sẽ hiển thị ở đây</p>
          </div>
        ) : (
