const ScriptRewriter: React.FC<{ showToast: (msg: string) => void }> = ({ showToast }) => {
  const [originalScript, setOriginalScript] = useState('');
  const [region, setRegion] = useState('standard');
  const [duration, setDuration] = useState(60);
  const [rewrittenScript, setRewrittenScript] = useState<AIScript | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isCopied, setIsCopied] = useState(false);

  const handleRewrite = async () => {
    if (!originalScript.trim()) return;
    setIsLoading(true);
    try {
      const result = await rewriteScriptWithAI(originalScript, region, duration);
      setRewrittenScript(result);
      showToast("Đã chuyển đổi kịch bản an toàn!");
    } catch (error) {
