const ScriptGenerator: React.FC<{ showToast: (msg: string) => void }> = ({ showToast }) => {
  const [productName, setProductName] = useState('');
  const [solution, setSolution] = useState('');
  const [scriptType, setScriptType] = useState('intro');
  const [region, setRegion] = useState('standard');
  const [duration, setDuration] = useState(30);
  const [script, setScript] = useState<any>(null);
  const [showVoiceModal, setShowVoiceModal] = useState(false);
  const [isAIProcessing, setIsAIProcessing] = useState(false);
  const [isCopied, setIsCopied] = useState(false);
  const [isVoiceCopied, setIsVoiceCopied] = useState(false);

  const vars: any = {
    wow: ["Trời ơi", "Tin được không", "Thật không thể tin nổi", "Ảo ma Canada", "Sốc thực sự", "OMG", "Chấn động", "Hết hồn chưa"],
    adj_pos: ["đỉnh cao", "xuất sắc", "tuyệt vời", "chân ái", "siêu xịn", "quá đã", "hết nước chấm", "mê ly", "sang - xịn - mịn", "đáng tiền", "10 điểm không có nhưng"],
    adj_neg: ["kinh khủng", "ám ảnh", "mệt mỏi", "chán nản", "bất lực", "khó chịu", "đau đầu", "stress", "trầm cảm", "xỉu up xỉu down"],
    time: ["30 giây", "5 phút", "tích tắc", "nháy mắt", "1 nốt nhạc", "vài ngày", "tức thì", "ngay lập tức"],
    urgent: ["hốt lẹ", "múc ngay", "chốt đơn", "rinh về", "săn liền", "bấm mua", "quất liền"],
    friend: ["con bạn thân", "bà chị", "nhỏ em", "đồng nghiệp", "mấy bà trên mạng", "idol tóp tóp"],
    visual_closeup: ["Zoom cận cảnh", "Quay sát vào", "Chiếu đèn vào", "Focus kỹ vào"],
    visual_action: ["Test thử", "Thoa lên tay", "Dùng trực tiếp", "Đập hộp", "Xé bao bì"],
  };

  const getRandomVar = (key: string) => vars[key][Math.floor(Math.random() * vars[key].length)];
  const fillTemplate = (text: string) => {
    return text
      .replace(/\[Wow\]/g, () => getRandomVar('wow'))
      .replace(/\[Adj_Pos\]/g, () => getRandomVar('adj_pos'))
      .replace(/\[Adj_Neg\]/g, () => getRandomVar('adj_neg'))
      .replace(/\[Time\]/g, () => getRandomVar('time'))
      .replace(/\[Urgent\]/g, () => getRandomVar('urgent'))
      .replace(/\[Friend\]/g, () => getRandomVar('friend'));
  };

  const scriptLibrary: any = {
    intro: {
      hooks: [
        { t: "[Wow]! Cuối cùng tui cũng tìm ra [Product] [Adj_Pos] nhất hệ mặt trời!", v: "Biểu cảm cực kỳ ngạc nhiên." },
        { t: "Khoan! Lướt qua là tiếc lắm nha, bí kíp này [Adj_Pos] lắm.", v: "Đưa tay ra hiệu dừng lại." },
        { t: "Thề luôn, biết đến em [Product] này sớm thì tui đã đỡ [Adj_Neg] biết bao nhiêu.", v: "Vỗ trán, lắc đầu tiến nuối." },
      ],
      agitates: [
        { t: "Mấy bà có công nhận là mỗi lần bị như vầy nó [Adj_Neg] kinh khủng không?", v: "Hình ảnh minh họa tình huống khó chịu." },
        { t: "Cứ tưởng tượng đang vội mà gặp cảnh này thì đúng là muốn [Adj_Neg] thiệt sự.", v: "Thở dài, buông xuôi." },
      ],
      solutions: [
        { t: "Nhưng mà từ lúc có em [Product] này là đời tui sang trang mới. Cái [Solution] của nó [Adj_Pos] lắm.", v: "Sản phẩm xuất hiện tỏa sáng." },
        { t: "May phước ghê, nhờ [Friend] giới thiệu em [Product] này nè. Nó hỗ trợ [Solution] trong [Time].", v: "Cầm sản phẩm xoay các góc." },
      ],
      proofs: [
        { t: "Nói có sách mách có chứng, mấy bà nhìn cái kết quả nè, [Adj_Pos] chưa?", v: "So sánh Trước/Sau." },
        { t: "Không phải mình tui khen đâu, nhiều người dùng rồi cũng ưng ý lắm.", v: "Chèn ảnh chụp màn hình phản hồi." },
      ],
      ctas: [
        { t: "Đang có ưu đãi tốt, mấy bà bấm vào giỏ hàng [Urgent] nha!", v: "Chỉ tay vào giỏ hàng." },
      ]
    }
  };

  const applyDialect = (text: string, region: string) => {
    if (!text) return "";
    let converted = text;
    if (region === 'hanoi') converted = converted.replace(/mấy bà/gi, "các bác").replace(/tui/gi, "em").replace(/nha/gi, "nhá");
    else if (region === 'saigon') converted = converted.replace(/không/gi, "hông").replace(/nhé/gi, "nha");
    return converted;
  };

  const generateScript = () => {
    if (!productName || !solution) return;
    const cleanProduct = sanitizeText(productName);
    const cleanSolution = sanitizeText(solution);
    const lib = scriptLibrary.intro;

    const scenes = [
      { time: "0:00", section: "HOOK", visual: lib.hooks[0].v, audio: applyDialect(fillTemplate(lib.hooks[0].t.replace(/\[Product\]/g, cleanProduct)), region) },
      { time: "0:05", section: "AGITATE", visual: lib.agitates[0].v, audio: applyDialect(fillTemplate(lib.agitates[0].t), region) },
      { time: "0:15", section: "SOLUTION", visual: lib.solutions[0].v, audio: applyDialect(fillTemplate(lib.solutions[0].t.replace(/\[Product\]/g, cleanProduct).replace(/\[Solution\]/g, cleanSolution)), region) },
      { time: "0:25", section: "CTA", visual: lib.ctas[0].v, audio: applyDialect(fillTemplate(lib.ctas[0].t), region) }
    ];

    setScript({ title: `Kịch bản ${scriptType} - ${duration}s`, scenes, isSafe: true });
    showToast("Đã tạo kịch bản ngẫu nhiên!");
  };

  const handleGenerateAIScript = async () => {
    if (!productName || !solution) return;
    setIsAIProcessing(true);
    try {
      const aiScript = await generateAdvancedScript(sanitizeText(productName), sanitizeText(solution), scriptType, region, duration);
      setScript(aiScript);
      showToast(`Đã tạo kịch bản AI ${duration}s!`);
    } catch (error) { 
      showToast("Lỗi AI. Đang sử dụng mẫu ngẫu nhiên."); 
      generateScript(); 
    } finally { 
      setIsAIProcessing(false); 
    }
  };

  const scriptTypeLabels: Record<string, string> = {
    intro: 'Quảng Cáo',
    usage: 'Hướng dẫn',
    review: 'Đánh giá',
    story: 'Kể chuyện'
  };

  const durations = [30, 60, 90, 120];

  const handleCopyVoice = () => {
    if (!script) return;
    const text = script.scenes.map((s: any) => s.audio).join(' ');
    copyToClipboard(text, () => {
      setIsVoiceCopied(true);
      showToast("Đã sao chép lời thoại!");
      setTimeout(() => setIsVoiceCopied(false), 2000);
    });
  };

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="space-y-4">
          <h2 className="text-lg font-bold text-slate-800 flex justify-between">Thông tin kịch bản</h2>

          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-500 uppercase flex items-center gap-1"><Clock size={12}/> Thời lượng video</label>
            <div className="grid grid-cols-4 gap-2">
              {durations.map(d => (
                <button key={d} onClick={() => setDuration(d)} className={`py-2 text-[11px] font-bold border rounded-lg transition ${duration === d ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-slate-300 text-slate-600 hover:bg-slate-50'}`}>{d}s</button>
              ))}
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-500 uppercase">Loại kịch bản</label>
            <div className="grid grid-cols-4 gap-2">
              {Object.keys(scriptTypeLabels).map(t => (
                <button key={t} onClick={() => setScriptType(t)} className={`py-2 text-[11px] font-medium border rounded-lg transition ${scriptType === t ? 'bg-indigo-50 border-indigo-500 text-indigo-700' : 'bg-white border-slate-300 text-slate-600'}`}>{scriptTypeLabels[t]}</button>
              ))}
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-500 uppercase flex items-center gap-1"><Map size={12}/> Giọng vùng miền</label>
            <div className="grid grid-cols-4 gap-2">
              {Object.keys(regionLabels).map(r => (
                 <button key={r} onClick={() => setRegion(r)} className={`py-1 text-[10px] font-bold border rounded transition-all ${region === r ? 'bg-indigo-600 text-white shadow-sm' : 'bg-white border-slate-300 text-slate-600 hover:bg-slate-50'}`}>{regionLabels[r]}</button>
              ))}
            </div>
          </div>

          <input className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-sm" placeholder="Tên sản phẩm..." value={productName} onChange={e => setProductName(e.target.value)} />
          <textarea className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-sm" placeholder="USP..." rows={3} value={solution} onChange={e => setSolution(e.target.value)} />

          <div className="flex gap-2">
            <button onClick={handleGenerateAIScript} disabled={isAIProcessing} className="flex-1 bg-indigo-600 text-white font-bold py-3 rounded-xl shadow-lg flex items-center justify-center text-sm hover:bg-indigo-700 transition active:scale-95">
              {isAIProcessing ? <RefreshCw className="animate-spin mr-2" /> : <BrainCircuit size={18} className="mr-2" />} TẠO KỊCH BẢN AI
            </button>
          </div>
        </div>

        <div className="bg-slate-50 p-4 rounded-xl border flex flex-col min-h-[400px]">
          <h2 className="text-lg font-bold mb-4 flex items-center justify-between">Kịch bản chi tiết</h2>
          {!script ? <div className="flex-1 flex flex-col items-center justify-center text-slate-400 opacity-50"><Film size={48} /></div> : (
            <div className="space-y-4 animate-fadeIn overflow-y-auto pr-2 custom-scrollbar">
               <div className="flex justify-between items-center pb-2 border-b">
                 <h3 className="font-bold text-indigo-700 text-sm truncate">{script.title}</h3>
                 <div className="flex gap-2">
                   <button onClick={() => setShowVoiceModal(true)} className="bg-indigo-600 text-white p-1.5 rounded hover:bg-indigo-700"><Mic size={14}/></button>
                   <button onClick={() => copyToClipboard(script.scenes.map((s:any) => s.audio).join('\n'), () => showToast("Đã sao chép!"))} className="p-1.5 rounded border bg-white text-slate-600"><Copy size={14}/></button>
                 </div>
               </div>
               {script.scenes.map((s:any, i:number) => (
                 <div key={i} className="bg-white p-3 rounded-lg border shadow-sm">
                   <div className="flex justify-between text-[10px] font-bold text-slate-500 mb-1">
                     <span className="bg-slate-100 px-2 py-0.5 rounded">{s.section}</span>
                     <span>{s.time}</span>
                   </div>
                   <p className="text-xs text-slate-500 italic mb-2">{s.visual}</p>
                   <p className="text-sm font-medium text-slate-800">"{s.audio}"</p>
                 </div>
               ))}
            </div>
          )}
        </div>
      </div>
      {showVoiceModal && script && (
        <div className="fixed inset-0 bg-black/60 z-[150] flex items-center justify-center p-4 backdrop-blur-sm">
