            <div className="p-6 overflow-y-auto whitespace-pre-wrap">{script.scenes.map((s:any)=>s.audio).join('\n\n')}</div>
            <div className="p-4 border-t flex justify-end">
                <button 
                  onClick={handleCopyVoice} 
                  className={`px-4 py-2 rounded-lg font-bold transition-all flex items-center ${isVoiceCopied ? 'bg-green-600 text-white' : 'bg-indigo-600 text-white hover:bg-indigo-700'}`}
