const POLICY_INSTRUCTIONS = `
TUYÊN THỦ NGHIÊM NGẶT LUẬT POLICY & PHONG CÁCH NỘI DUNG:
1. TUYỆT ĐỐI KHÔNG LẶP TỪ: Không sử dụng lặp lại các tính từ, trạng từ hoặc cấu trúc câu trong cùng một kịch bản. Ví dụ: Nếu cảnh 1 dùng "tuyệt vời", cảnh 2 phải dùng "xuất sắc", "ưng ý" hoặc "hài lòng".
2. GIỌNG ĐIỆU: Thân thiện, gần gũi, tự nhiên như một người bạn đang kể chuyện hoặc chia sẻ trải nghiệm thật, không dùng giọng đọc quảng cáo khô khan.
3. TỪ CẤM POLICY: Không dùng "trị dứt điểm", "cam kết 100%", "thuốc", "điều trị", "vĩnh viễn", "tuyệt đối". Thay bằng "hỗ trợ", "cải thiện", "yên tâm", "hiệu quả lâu dài".
4. TỪ KHÓA BỊ BÓP TƯƠNG TÁC: Hạn chế "giá", "tiền", "mua", "bán" ở 3 giây đầu.
5. CẤU TRÚC: Phải có nhịp điệu, ngắt nghỉ tự nhiên.
`;

const getRegionInstruction = (region: string) => {
  const regions: Record<string, string> = {
    standard: "Tiếng Việt phổ thông, dễ nghe, chuẩn mực.",
    hanoi: "Giọng Hà Nội: Thanh lịch, nhẹ nhàng, dùng từ ngữ tinh tế, đúng chuẩn thủ đô (ví dụ: dùng 'nhé', 'nhỉ', 'thế à').",
    saigon: "Giọng Sài Gòn: Năng động, cởi mở, dùng từ ngữ hiện đại (ví dụ: 'nè', 'nha', 'hông', 'thiệt sự').",
    mientay: "Giọng Miền Tây (Cần Thơ/Vĩnh Long): Chân chất, hào sảng, dùng từ địa phương dân dã (ví dụ: 'tui', 'dữ thần', 'hết sảy', 'nghen').",
    hue: "Giọng Huế: Nhẹ nhàng, từ tốn, sử dụng từ ngữ đặc trưng cố đô (ví dụ: 'mô', 'tê', 'răng', 'rứa', 'mi').",
    nghetinh: "Giọng Nghệ Tĩnh (Nghệ An/Hà Tĩnh): Mộc mạc, tiết kiệm, dùng từ địa phương mạnh mẽ (ví dụ: 'choa', 'mần', 'nỏ', 'rành').",
    danang: "Giọng Đà Nẵng/Quảng Nam: Bộc trực, thân thiện, âm sắc đặc trưng miền Trung (ví dụ: 'ni', 'tê', 'rứa nè').",
    haiphong: "Giọng Hải Phòng: Thẳng thắn, mạnh mẽ, cá tính, không lòng vòng."
  };
  return regions[region] || regions.standard;
};

/**
 * Chuyển đổi kịch bản từ nguồn bên ngoài thành bản chuẩn Policy và phương ngữ
 */
export const rewriteScriptWithAI = async (
  originalScript: string,
  region: string,
  duration: number
): Promise<AIScript> => {
  const prompt = `Bạn là chuyên gia sáng tạo kịch bản video. Hãy biến đổi kịch bản gốc dưới đây thành một bản MỚI hoàn toàn.

  KỊCH BẢN GỐC: "${originalScript}"
  YÊU CẦU PHƯƠNG NGỮ: ${getRegionInstruction(region)}
  THỜI LƯỢNG MỤC TIÊU: ${duration} giây.

  ${POLICY_INSTRUCTIONS}

  YÊU CẦU CỤ THỂ:
  - Giữ lại linh hồn và thông điệp nhưng viết lại 100% lời thoại.
  - Sắp xếp lại nhịp phim để đạt đúng ${duration} giây.
  - Sử dụng vốn từ phong phú để tránh lặp lại bất kỳ từ ngữ nào giữa các phân đoạn.
  - Đảm bảo lời thoại nghe như tiếng nói hàng ngày, không phải văn viết.

  Trả về JSON:
  {
    "title": "Kịch bản chuyển đổi an toàn - Giọng ${region}",
    "scenes": [
      {"time": "0:00 - 0:05", "section": "HOOK", "visual": "mô tả hình ảnh cuốn hút", "audio": "lời thoại tự nhiên"},
      ...
    ],
    "isSafe": true
  }`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: { responseMimeType: "application/json" }
  });

  return JSON.parse(response.text || '{}');
};

