// --- Utility: Toast Notification ---
const Toast: React.FC<{ message: string | null; onClose: () => void }> = ({ message, onClose }) => {
  useEffect(() => {
    if (!message) return;
    const timer = setTimeout(onClose, 2500);
    return () => clearTimeout(timer);
  }, [message, onClose]);

  if (!message) return null;

  return (
    <div className="fixed bottom-4 right-4 bg-slate-900 text-white px-5 py-3 rounded-2xl shadow-2xl flex items-center animate-fadeIn z-[100] border border-white/10 backdrop-blur-md">
      <CheckCircle size={18} className="text-emerald-400 mr-3" />
      <span className="text-sm font-semibold">{message}</span>
    </div>
  );
};

// --- Utility: Copy ---
const copyToClipboard = (text: string, onSuccess?: () => void) => {
  try {
    const textArea = document.createElement("textarea");
    textArea.value = text;
    textArea.style.position = "fixed";
    textArea.style.left = "-9999px";
    document.body.appendChild(textArea);
    textArea.select();
    const successful = document.execCommand('copy');
    document.body.removeChild(textArea);
    if (successful && onSuccess) onSuccess();
  } catch (err) {
    console.error('Lỗi sao chép', err);
  }
};

