export const rewriteScriptWithAI = async (
  originalScript: string,
  region: string,
  duration: number
): Promise<AIScript> => {
  const prompt = `Bạn là một chuyên gia sáng tạo nội dung kịch bản video. 
  NHIỆM VỤ: Chuyển đổi kịch bản gốc sau đây thành một kịch bản MỚI, hấp dẫn hơn và TUYỆT ĐỐI TUÂN THỦ CHÍNH SÁCH.

  Kịch bản gốc: "${originalScript}"
  Phương ngữ yêu cầu: ${getRegionInstruction(region)}
  Thời lượng mục tiêu: ${duration} giây.

  ${POLICY_INSTRUCTIONS}

  YÊU CẦU:
  1. Viết lại hoàn toàn lời thoại: Sử dụng từ ngữ phong phú, KHÔNG LẶP TỪ.
  2. Lách tất cả các từ cấm bằng cách dùng từ đồng nghĩa tinh tế (VD: "thuốc" -> "em này", "trị dứt điểm" -> "hỗ trợ cải thiện rõ rệt").
  3. Đảm bảo 3s đầu (Hook) cực kỳ cuốn hút theo đúng phong cách địa phương.

  Trả về JSON chuẩn format:
  {
    "title": "Kịch bản chuyển đổi - Giọng ${region}",
    "scenes": [
      {"time": "0:00 - 0:05", "section": "HOOK", "visual": "mô tả hình ảnh mới", "audio": "lời thoại mới an toàn"},
      ...
    ],
    "isSafe": true
  }`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          scenes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                time: { type: Type.STRING },
                section: { type: Type.STRING },
                visual: { type: Type.STRING },
                audio: { type: Type.STRING }
