    if (region === 'hanoi' || region === 'haiphong') {
      converted = converted.replace(/mấy bà/gi, "các bác").replace(/tui/gi, "em").replace(/nha/gi, "nhé").replace(/hông/gi, "không");
    } else if (region === 'hue' || region === 'nghetinh') {
      converted = converted.replace(/mấy bà/gi, "mấy o").replace(/tôi/gi, "tui").replace(/nha/gi, "hỉ");
    } else if (region === 'saigon' || region === 'mientay') {
      converted = converted.replace(/không/gi, "hông").replace(/nhé/gi, "nha");
    }
    return converted;
  };

  const getSectionTemplate = (type: string, sectionName: string) => {
    const library = scriptLibrary[type] || scriptLibrary['intro']; 
