// Global Policy Instructions for the AI
const POLICY_INSTRUCTIONS = `
TUYÊN THỦ NGHIÊM NGẶT LUẬT POLICY & PHONG CÁCH NỘI DUNG:
1. TUYỆT ĐỐI KHÔNG LẶP TỪ: Không sử dụng lặp lại các tính từ, trạng từ hoặc cấu trúc câu trong cùng một kịch bản. Sử dụng vốn từ đồng nghĩa phong phú để tạo sự lôi cuốn.
2. GIỌNG ĐIỆU: Phải thân thiện, gần gũi, tự nhiên như người thật đang chia sẻ kinh nghiệm cho người nhà. Tránh văn phong quảng cáo sáo rỗng.
3. TỪ CẤM POLICY: Không dùng "trị dứt điểm", "cam kết 100%", "thuốc", "điều trị", "vĩnh viễn", "tuyệt đối". Thay bằng "hỗ trợ", "cải thiện", "yên tâm", "hiệu quả bền lâu".
4. TỪ KHÓA BỊ BÓP TƯƠNG TÁC: Hạn chế "giá", "tiền", "mua", "bán" ở 3 giây đầu (Hook).
`;

const getRegionInstruction = (region: string) => {
  const regions: Record<string, string> = {
    standard: "Tiếng Việt phổ thông, dễ nghe, chuẩn mực.",
    hanoi: "Giọng Hà Nội: Thanh lịch, dùng từ ngữ tinh tế, đúng chuẩn thủ đô (ví dụ: dùng 'nhé', 'nhỉ', 'thế à').",
    saigon: "Giọng Sài Gòn: Năng động, cởi mở, dùng từ ngữ hiện đại (ví dụ: 'nè', 'nha', 'hông', 'thiệt sự').",
    mientay: "Giọng Miền Tây: Chân chất, hào sảng, dùng từ dân dã (ví dụ: 'tui', 'hết sảy', 'nghen').",
    hue: "Giọng Huế: Nhẹ nhàng, từ tốn, sử dụng từ địa phương đặc trưng (ví dụ: 'mô', 'tê', 'răng', 'rứa').",
    nghean: "Giọng Nghệ An: Mộc mạc, chân tình, sử dụng từ ngữ địa phương đặc trưng của xứ Nghệ (ví dụ: 'chi', 'mần', 'răng', 'rứa', 'nỏ', 'choa', 'rành'). Lời thoại nghe phải rành mạch nhưng vẫn rất gần gũi.",
    nghetinh: "Giọng Nghệ Tĩnh: Mạnh mẽ, chân phương, dùng từ địa phương đặc trưng.",
    danang: "Giọng Đà Nẵng: Bộc trực, thân thiện, dùng từ ngữ đặc trưng miền Trung.",
    haiphong: "Giọng Hải Phòng: Thẳng thắn, mạnh mẽ, cá tính."
  };
  return regions[region] || regions.standard;
};

/**
 * Transforms an existing script into a new, policy-safe version.
 */
export const rewriteScriptWithAI = async (
  originalScript: string,
  region: string,
  duration: number
): Promise<AIScript> => {
  const prompt = `Bạn là một chuyên gia sáng tạo nội dung kịch bản video. 
  NHIỆM VỤ: Chuyển đổi kịch bản gốc sau đây thành một kịch bản MỚI cho giọng ${region}.

  Kịch bản gốc: "${originalScript}"
  Phương ngữ yêu cầu: ${getRegionInstruction(region)}
  Thời lượng mục tiêu: ${duration} giây.

  ${POLICY_INSTRUCTIONS}

  YÊU CẦU:
  1. Viết lại hoàn toàn lời thoại: Sử dụng từ ngữ phong phú, KHÔNG LẶP TỪ.
  2. GIỌNG ĐIỆU: Phải CỰC KỲ GẦN GŨI, thân mật.
  3. Lách tất cả các từ cấm bằng cách dùng từ đồng nghĩa tinh tế.

  Trả về JSON chuẩn format:
  {
    "title": "Kịch bản chuyển đổi - Giọng ${region}",
    "scenes": [
      {"time": "0:00 - 0:05", "section": "HOOK", "visual": "mô tả hình ảnh", "audio": "lời thoại"},
      ...
    ],
    "isSafe": true
  }`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          scenes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                time: { type: Type.STRING },
                section: { type: Type.STRING },
                visual: { type: Type.STRING },
                audio: { type: Type.STRING }
              },
              required: ["time", "section", "visual", "audio"]
            }
          },
          isSafe: { type: Type.BOOLEAN }
        },
        required: ["title", "scenes", "isSafe"]
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

