`;

const getRegionDescription = (region: string) => {
  switch (region) {
    case 'north': return 'Giọng Miền Bắc (Hà Nội), thanh lịch, nhẹ nhàng.';
    case 'south': return 'Giọng Miền Nam (Sài Gòn), năng động, gần gũi.';
    case 'central': return 'Giọng Miền Trung (Huế/Đà Nẵng), truyền cảm.';
    case 'nghean': return 'Giọng Nghệ An: Mộc mạc, chân chất, sử dụng các từ ngữ địa phương đặc trưng như "chi", "mần", "răng", "rứa", "nỏ", "choa", "rành" một cách tự nhiên.';
    default: return 'Tiếng Việt phổ thông.';
  }
};

/**
 * Transforms an existing script into a new, policy-safe version.
 */
export const rewriteScriptWithAI = async (
  originalScript: string,
  region: string,
  duration: number
): Promise<AIScript> => {
  const prompt = `Bạn là một chuyên gia sáng tạo nội dung kịch bản video. 
  NHIỆM VỤ: Chuyển đổi kịch bản gốc sau đây thành một kịch bản MỚI cho giọng ${region}.

  Kịch bản gốc: "${originalScript}"
  Giọng văn yêu cầu: ${getRegionDescription(region)}.
  Thời lượng mục tiêu: ${duration} giây.

  ${POLICY_INSTRUCTIONS}

  YÊU CẦU:
  1. Phân tích kịch bản gốc để giữ lại ý tưởng chính nhưng viết lại 100% lời thoại.
  2. Tuyệt đối KHÔNG LẶP TỪ ngữ giữa các phân đoạn.
  3. Lách tất cả các từ cấm bằng cách dùng từ đồng nghĩa tinh tế.
  4. Đảm bảo 3s đầu (Hook) cực kỳ cuốn hút theo đúng phong cách giọng ${region}.

  Trả về JSON chuẩn format:
  {
    "title": "Kịch bản chuyển đổi - Giọng ${region}",
    "scenes": [
      {"time": "0:00 - 0:05", "section": "HOOK", "visual": "mô tả hình ảnh mới", "audio": "lời thoại mới an toàn"},
      ...
    ],
    "isSafe": true
  }`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          scenes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                time: { type: Type.STRING },
                section: { type: Type.STRING },
                visual: { type: Type.STRING },
                audio: { type: Type.STRING }
              },
              required: ["time", "section", "visual", "audio"]
            }
          },
          isSafe: { type: Type.BOOLEAN }
        },
        required: ["title", "scenes", "isSafe"]
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

