const Toast: React.FC<{ message: string | null; onClose: () => void }> = ({ message, onClose }) => {
  useEffect(() => {
    if (!message) return;
    const timer = setTimeout(onClose, 2500);
    return () => clearTimeout(timer);
  }, [message, onClose]);

  if (!message) return null;

  return (
    <div className="fixed bottom-4 right-4 bg-slate-800 text-white px-4 py-3 rounded-lg shadow-lg flex items-center animate-fadeIn z-[100] border border-slate-700">
      <CheckCircle size={16} className="text-green-400 mr-2" />
      <span className="text-sm font-medium">{message}</span>
    </div>
  );
};

// --- Utility: Robust Copy Function ---
const copyToClipboard = (text: string, onSuccess?: () => void) => {
  try {
    const textArea = document.createElement("textarea");
    textArea.value = text;
    textArea.style.position = "fixed";
    textArea.style.left = "-9999px";
    textArea.style.top = "0";
    document.body.appendChild(textArea);
    textArea.focus();
    textArea.select();
    const successful = document.execCommand('copy');
    document.body.removeChild(textArea);
    if (successful && onSuccess) {
      onSuccess();
    }
  } catch (err) {
    console.error('Lỗi sao chép', err);
  }
};

// --- Utility: Advanced Policy Sanitizer ---
const sanitizeText = (text: string) => {
  if (!text || typeof text !== 'string') return "";
  let cleanText = text;
  const policyRules = [
    { wrong: /(trị|chữa) dứt điểm/gi, right: "hỗ trợ cải thiện" },
    { wrong: /(trị|chữa) khỏi( hẳn)?/gi, right: "giúp cải thiện" },
    { wrong: /cam kết 100%/gi, right: "rất yên tâm" },
    { wrong: /chắc chắn (khỏi|hết)/gi, right: "có hiệu quả tốt" },
    { wrong: /vĩnh viễn/gi, right: "lâu dài" },
    { wrong: /tuyệt đối/gi, right: "tối đa" },
    { wrong: /hoàn tiền/gi, right: "hỗ trợ đổi trả" },
    { wrong: /thuốc/gi, right: "sản phẩm" }, 
    { wrong: /điều trị/gi, right: "hỗ trợ" },
    { wrong: /bệnh viện/gi, right: "nơi uy tín" },
    { wrong: /bác sĩ/gi, right: "chuyên gia" },
  ];
  policyRules.forEach(rule => {
    cleanText = cleanText.replace(rule.wrong, rule.right);
  });
  return cleanText;
};

