    if (!script) return;
    const text = script.scenes.map((s: any) => `[${s.time}] ${s.section}\n- Hình ảnh: ${s.visual}\n- Lời thoại: ${s.audio}`).join('\n\n');
    copyToClipboard(text, () => {
      setIsCopied(true);
      showToast("Đã sao chép kịch bản!");
      setTimeout(() => setIsCopied(false), 2000);
    });
  };

  const handleCopyVoice = () => {
    if (!script) return;
    const text = script.scenes.map((s: any) => s.audio).join(' ');
    copyToClipboard(text, () => {
      setIsVoiceCopied(true);
      showToast("Đã sao chép lời thoại!");
      setTimeout(() => setIsVoiceCopied(false), 2000);
    });
