          </div>
        </div>
      )}

      <div className="grid gap-4">
        {hooks.length === 0 ? (
          <div className="text-center py-12 bg-slate-50/50 rounded-xl border border-dashed border-slate-200">
            <Layers className="mx-auto mb-3 opacity-10" size={64} />
            <p className="text-slate-400 font-medium italic text-sm">Nhập tên sản phẩm!</p>
          </div>
        ) : (
