            <div key={i} className="bg-white p-4 rounded-xl border border-slate-200 hover:border-indigo-400 flex justify-between items-center group transition-all hover:shadow-lg animate-fadeIn relative">
              <div className="flex-1 pr-4">
                <div className="flex items-center gap-2 mb-1.5">
                  <span className="text-[10px] font-semibold bg-indigo-50 text-indigo-600 px-2 py-0.5 rounded border border-indigo-100">
                    {categoryLabels[h.category] || h.category}
                  </span>
                  <span className="text-indigo-400 font-medium text-[10px]">#0{i+1}</span>
                </div>
                <p className="font-semibold text-slate-800 leading-snug text-sm md:text-base cursor-pointer hover:text-indigo-600 transition-colors" onClick={() => copyToClipboard(h.hook, () => showToast("Đã sao chép Hook!"))}>
                  {h.hook}
                </p>
              </div>
              <div className="flex gap-2 shrink-0">
                <button 
                  onClick={() => handleGenerateScriptFromHook(h.hook)}
                  className="p-2.5 bg-indigo-50 text-indigo-600 rounded-lg hover:bg-indigo-600 hover:text-white transition-all transform hover:scale-110 shadow-sm"
                  title="Tạo kịch bản review từ Hook này"
                >
                  <Video size={18} />
                </button>
                <button 
                  onClick={() => copyToClipboard(h.hook, () => showToast("Đã sao chép!"))}
                  className="p-2.5 text-slate-400 hover:text-indigo-600 transition-colors bg-white border border-slate-100 rounded-lg shadow-sm"
                >
                  <Copy size={18} />
                </button>
              </div>
            </div>
          ))
        )}
      </div>

      {viewScript && (
        <div className="fixed inset-0 bg-black/60 z-[120] flex items-center justify-center p-4 backdrop-blur-sm animate-fadeIn">
          <div className="bg-white rounded-xl shadow-2xl max-w-2xl w-full max-h-[90vh] flex flex-col">
            <div className="p-4 border-b flex justify-between items-center bg-indigo-50 font-bold">
              <span className="flex items-center text-indigo-800 text-sm"><ShieldCheck className="mr-2 text-green-600"/> Kịch bản review an toàn chính sách</span>
              <button onClick={() => setViewScript(null)}><X size={20}/></button>
            </div>
            <div className="p-6 overflow-y-auto space-y-4 custom-scrollbar">
               <h3 className="font-bold text-indigo-700 text-center border-b pb-3 leading-tight text-base">{viewScript.title}</h3>
