                 <div key={i} className="bg-slate-50 p-4 rounded-lg border border-slate-200 shadow-sm transition-all hover:border-indigo-200">
                   <div className="flex justify-between text-[10px] font-semibold text-indigo-500 mb-2">
                     <span className="bg-indigo-100 px-2 py-0.5 rounded">{s.section}</span><span>{s.time}</span>
                   </div>
                   <div className="flex items-start gap-3">
                     <Camera size={16} className="text-slate-400 mt-1 shrink-0" />
