      </div>

      {hooks.length > 0 && (
        <div className="flex flex-wrap gap-2 py-2 border-b border-slate-100 overflow-x-auto whitespace-nowrap custom-scrollbar">
          {Object.entries(categoryLabels).map(([id, label]: [string, any]) => (
            <button 
              key={id} 
              onClick={() => setCategory(id)}
              className={`px-4 py-1.5 rounded-full text-xs font-medium border transition-all ${category === id ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-slate-200 text-slate-500 hover:border-indigo-300'}`}
            >
              {label}
            </button>
          ))}
        </div>
      )}

      {isGeneratingScript && (
        <div className="fixed inset-0 bg-black/20 z-[110] flex items-center justify-center backdrop-blur-sm">
          <div className="bg-white p-6 rounded-xl shadow-xl flex flex-col items-center animate-bounce">
            <BrainCircuit className="h-10 w-10 text-indigo-600 animate-pulse" />
            <p className="mt-2 font-semibold text-indigo-900 text-sm">Đang viết kịch bản</p>
          </div>
        </div>
      )}

      <div className="grid gap-4">
        {hooks.length === 0 ? (
          <div className="text-center py-12 bg-slate-50/50 rounded-xl border border-dashed border-slate-200">
            <Layers className="mx-auto mb-3 opacity-10" size={64} />
            <p className="text-slate-400 font-medium italic text-sm">Nhập tên sản phẩm!</p>
          </div>
        ) : (
          filteredHooks.map((h, i) => (
            <div key={i} className="bg-white p-4 rounded-xl border border-slate-200 hover:border-indigo-400 flex justify-between items-center group transition-all hover:shadow-lg animate-fadeIn relative">
              <div className="flex-1 pr-4">
                <div className="flex items-center gap-2 mb-1.5">
                  <span className="text-[10px] font-semibold bg-indigo-50 text-indigo-600 px-2 py-0.5 rounded border border-indigo-100">
                    {categoryLabels[h.category] || h.category}
                  </span>
                  <span className="text-indigo-400 font-medium text-[10px]">#0{i+1}</span>
                </div>
                <p className="font-semibold text-slate-800 leading-snug text-sm md:text-base cursor-pointer hover:text-indigo-600 transition-colors" onClick={() => copyToClipboard(h.hook, () => showToast("Đã sao chép Hook!"))}>
                  {h.hook}
                </p>
              </div>
              <div className="flex gap-2 shrink-0">
                <button 
                  onClick={() => handleGenerateScriptFromHook(h.hook)}
                  className="p-2.5 bg-indigo-50 text-indigo-600 rounded-lg hover:bg-indigo-600 hover:text-white transition-all transform hover:scale-110 shadow-sm"
                  title="Tạo kịch bản review từ Hook này"
                >
                  <Video size={18} />
                </button>
                <button 
                  onClick={() => copyToClipboard(h.hook, () => showToast("Đã sao chép!"))}
                  className="p-2.5 text-slate-400 hover:text-indigo-600 transition-colors bg-white border border-slate-100 rounded-lg shadow-sm"
                >
                  <Copy size={18} />
                </button>
              </div>
            </div>
          ))
        )}
      </div>

      {viewScript && (
        <div className="fixed inset-0 bg-black/60 z-[120] flex items-center justify-center p-4 backdrop-blur-sm animate-fadeIn">
          <div className="bg-white rounded-xl shadow-2xl max-w-2xl w-full max-h-[90vh] flex flex-col">
            <div className="p-4 border-b flex justify-between items-center bg-indigo-50 font-bold">
              <span className="flex items-center text-indigo-800 text-sm"><ShieldCheck className="mr-2 text-green-600"/> Kịch bản review an toàn chính sách</span>
              <button onClick={() => setViewScript(null)}><X size={20}/></button>
            </div>
            <div className="p-6 overflow-y-auto space-y-4 custom-scrollbar">
               <h3 className="font-bold text-indigo-700 text-center border-b pb-3 leading-tight text-base">{viewScript.title}</h3>
               {viewScript.scenes.map((s, i) => (
                 <div key={i} className="bg-slate-50 p-4 rounded-lg border border-slate-200 shadow-sm transition-all hover:border-indigo-200">
                   <div className="flex justify-between text-[10px] font-semibold text-indigo-500 mb-2">
                     <span className="bg-indigo-100 px-2 py-0.5 rounded">{s.section}</span><span>{s.time}</span>
                   </div>
                   <div className="flex items-start gap-3">
                     <Camera size={16} className="text-slate-400 mt-1 shrink-0" />
                     <p className="text-xs text-slate-600 italic leading-relaxed">{s.visual}</p>
                   </div>
                   <div className="mt-3 flex items-start gap-3 bg-white p-3 rounded border border-slate-100 shadow-inner">
                     <Mic size={16} className="text-pink-500 mt-1 shrink-0" />
                     <p className="text-sm font-medium text-slate-800 leading-relaxed">"{s.audio}"</p>
                   </div>
                 </div>
               ))}
            </div>
            <div className="p-4 border-t flex gap-2 justify-end bg-slate-50 rounded-b-xl">
               <button 
                 onClick={() => setShowVoiceModal(true)} 
                 className="px-4 py-2 bg-white border border-indigo-200 text-indigo-600 rounded-lg font-semibold flex items-center hover:bg-indigo-50 transition shadow-sm text-sm"
               >
                 <Mic size={18} className="mr-2"/> Trích xuất giọng nói
               </button>
               <button 
                 onClick={() => copyToClipboard(viewScript.scenes.map(s => `[${s.section}] ${s.audio}`).join('\n\n'), () => {
                   setIsScriptCopied(true);
                   showToast("Đã sao chép kịch bản!");
                   setTimeout(() => setIsScriptCopied(false), 2000);
                 })} 
                 className={`px-6 py-2 rounded-lg font-semibold flex items-center shadow-lg transition-all text-sm ${isScriptCopied ? 'bg-green-600 text-white' : 'bg-indigo-600 text-white hover:bg-indigo-700'}`}
               >
                 {isScriptCopied ? <><Check size={18} className="mr-2"/> Đã sao chép</> : <><Copy size={18} className="mr-2"/> Sao chép kịch bản</>}
               </button>
            </div>
          </div>
        </div>
      )}

      {showVoiceModal && viewScript && (
        <div className="fixed inset-0 bg-black/60 z-[130] flex items-center justify-center p-4 backdrop-blur-sm animate-fadeIn">
          <div className="bg-white rounded-xl shadow-2xl max-w-lg w-full max-h-[80vh] flex flex-col">
            <div className="p-4 border-b flex justify-between items-center bg-indigo-50 font-bold">
              <span className="flex items-center text-indigo-800 text-sm"><Mic size={18} className="mr-2"/> Lời thoại review</span>
              <button onClick={() => setShowVoiceModal(false)}><X size={20}/></button>
            </div>
            <div className="p-6 overflow-y-auto text-base leading-loose font-normal text-slate-700 bg-slate-50/50 italic">
              {getVoiceOnlyText()}
            </div>
            <div className="p-4 border-t flex justify-end bg-slate-50 rounded-b-xl">
              <button 
                onClick={() => copyToClipboard(viewScript.scenes.map(s => s.audio).join(' '), () => {
                  setIsVoiceCopied(true);
                  showToast("Đã sao chép lời thoại!");
                  setTimeout(() => setIsVoiceCopied(false), 2000);
                })} 
                className={`px-6 py-2 rounded-lg font-semibold flex items-center shadow-md transition-all text-sm ${isVoiceCopied ? 'bg-green-600 text-white' : 'bg-indigo-600 text-white hover:bg-indigo-700'}`}
              >
                {isVoiceCopied ? <><Check size={18} className="mr-1"/> Đã sao chép</> : <><Copy size={18} className="mr-2"/> Sao chép lời thoại</>}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const PolicyGuide: React.FC<{ showToast: (msg: string) => void }> = ({ showToast }) => {
  const [input, setInput] = useState('');
  const [res, setRes] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [expanded, setExpanded] = useState<string | null>(null);
  const [isCopied, setIsCopied] = useState(false);

  const check = async () => {
    if (!input) return;
    setLoading(true);
    try { setRes(await analyzeScriptWithAI(input)); showToast("Đã quét chính sách!"); } catch { setRes({ status:'safe', violations:[], warnings:[], suggestedScript: sanitizeText(input) }); }
    finally { setLoading(false); }
  };

  const handleCopySuggestion = () => {
    if (!res) return;
    copyToClipboard(res.suggestedScript, () => {
      setIsCopied(true);
      showToast("Đã sao chép bản gợi ý!");
      setTimeout(() => setIsCopied(false), 2000);
    });
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      <div className="bg-indigo-50 border border-indigo-100 rounded-xl p-6 space-y-4">
        <h2 className="text-lg font-bold flex items-center"><ShieldCheck className="mr-2 h-6 w-6 text-indigo-600" /> Phân tích và sửa lỗi chính sách nền tảng</h2>
        <textarea className="w-full p-4 border rounded-lg h-32 font-medium text-slate-700 focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm" placeholder="Dán nội dung cần kiểm tra..." value={input} onChange={e => setInput(e.target.value)} />
        <button onClick={check} disabled={loading} className="bg-indigo-600 text-white font-semibold py-3 px-6 rounded-lg w-full flex justify-center items-center hover:bg-indigo-700 transition shadow-md disabled:opacity-50 text-sm">
            {loading ? <RefreshCw className="animate-spin mr-2" /> : <Wand2 className="mr-2" />} Quét & sửa lỗi ngay
        </button>
        {res && (
          <div className={`p-4 rounded-lg border mt-4 ${res.status === 'danger' ? 'bg-red-50 border-red-200' : 'bg-green-50 border-green-200'}`}>
             <div className="flex gap-2 items-center font-bold text-sm mb-2">
               {res.status === 'danger' ? <AlertOctagon className="text-red-600"/> : <CheckCircle className="text-green-600"/>}
               {res.status === 'danger' ? 'Phát hiện vi phạm' : 'An toàn nền tảng'}
             </div>
             <div className="flex flex-wrap gap-2 mb-4">{[...res.violations, ...res.warnings].map((w:string,i:number)=>(<span key={i} className={`px-2 py-1 bg-white border text-[10px] font-semibold ${res.violations.includes(w) ? 'text-red-600 border-red-100' : 'text-yellow-600 border-yellow-100'}`}>"{w}"</span>))}</div>
             <div className="bg-white rounded-lg border overflow-hidden shadow-sm">
               <div className={`px-4 py-2 text-white text-xs font-semibold flex justify-between items-center transition-colors ${isCopied ? 'bg-green-600' : 'bg-indigo-600'}`}>
                 <span>Gợi ý bản chuẩn chính sách</span>
                 <button onClick={handleCopySuggestion} className="flex items-center gap-1 hover:opacity-80">
                   {isCopied ? <><Check size={14}/> Đã sao chép</> : <><Copy size={14}/> Sao chép</>}
                 </button>
               </div>
               <div className="p-4 text-sm font-medium text-slate-700 leading-relaxed">{res.suggestedScript}</div>
             </div>
          </div>
        )}
      </div>

      <div className="space-y-4">
        <h2 className="text-lg font-bold border-b pb-2 text-slate-800">Bộ nguyên tắc quy định (chính thức)</h2>

        <RuleSection id="goal" title="1) Mục tiêu số 1: Giữ an toàn thương hiệu" active={expanded} set={setExpanded}>
          <p className="font-semibold text-indigo-600 mb-2">Thứ tự ưu tiên:</p>
          <ul className="list-disc ml-5 space-y-1">
            <li><strong>An toàn phát ngôn:</strong> Không gây tranh cãi, không bị cắt ghép sai ý.</li>
            <li><strong>Giữ thiện cảm:</strong> Không trịch thượng, không khoe khoang, không dìm ai.</li>
            <li><strong>Bán hàng hiệu quả:</strong> Truyền đạt rõ lợi ích, thuyết phục, kêu gọi hành động cụ thể.</li>
          </ul>
        </RuleSection>

        <RuleSection id="community" title="2) Tiêu chuẩn cộng đồng (Facebook & TikTok)" active={expanded} set={setExpanded}>
          <div className="space-y-4">
            <div className="flex gap-2">
              <ShieldAlert className="text-red-600 shrink-0" size={20} />
              <div>
                <h4 className="font-bold text-red-800 text-sm">Các vi phạm nghiêm trọng (Dễ bị bay kênh)</h4>
                <ul className="list-disc ml-5 mt-2 space-y-2 text-xs text-slate-700">
                  <li><strong>Nội dung bạo lực/nhạy cảm:</strong> Các cảnh quay máu me, vũ khí hoặc hành vi nguy hiểm.</li>
                  <li><strong>Thông tin sai lệch:</strong> Các tuyên bỏ sai sự thật về y tế, chính trị hoặc tin giả.</li>
                  <li><strong>Gian lận & lừa đảo:</strong> Hứa hẹn trúng thưởng vô lý, đa cấp, kêu gọi đầu tư rủi ro.</li>
                  <li><strong>Quyền riêng tư:</strong> Tiết lộ thông tin cá nhân của người khác (SĐT, địa chỉ, căn cước...).</li>
                  <li><strong>Bắt nạt & quấy rối:</strong> Ngôn từ thù ghét, miệt thị ngoại hình (body shaming), tấn công cá nhân.</li>
