import { GoogleGenAI, Type } from "@google/genai";

// Initialize AI directly with the provided API key
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export interface AIScriptScene {
  time: string;
  section: string;
  visual: string;
  audio: string;
}

export interface AIScript {
  title: string;
  scenes: AIScriptScene[];
  isSafe: boolean;
}

export interface AIHookResult {
  category: string;
  hook: string;
}

// Global Policy Instructions for the AI
const POLICY_INSTRUCTIONS = `
TUYÊN THỦ NGHIÊM NGẶT LUẬT POLICY & TIÊU CHUẨN CỘNG ĐỒNG:
1. KHÔNG sử dụng các từ tuyệt đối hóa: "trị dứt điểm", "chữa khỏi", "cam kết 100%", "vĩnh viễn", "tuyệt đối", "100%", "chắc chắn hết".
2. KHÔNG sử dụng từ liên quan đến y tế/thuốc: "thuốc", "điều trị", "bệnh viện", "bác sĩ" (thay bằng "sản phẩm", "hỗ trợ", "chuyên gia", "nơi uy tín").
3. KHÔNG sử dụng từ ngữ gây chia rẽ: "giàu", "nghèo", "sang", "hèn", "vô học", "nhà giàu" (thay bằng "người có điều kiện", "tiết kiệm", "phù hợp hoàn cảnh").
4. KHÔNG so sánh tiêu cực/dìm đối thủ: Không chê bai sản phẩm khác, không dùng từ "dỏm", "lởm", "đểu".
5. KHÔNG sử dụng từ nhạy cảm dễ bị bóp tương tác: Hạn chế "giá", "tiền", "mua", "bán", "chốt đơn" trực tiếp trong 3s đầu.
6. TUÂN THỦ 10 QUY ĐỊNH NỀT TẢNG: Không chính trị, không tôn giáo, không bạo lực, không hứa hẹn phi thực tế.
7. GIỌNG VĂN: Luôn tự nhiên, thân thiện như người thật chia sẻ, không máy móc quảng cáo.
8. KHÔNG LẶP TỪ: Tuyệt đối không lặp lại các từ ngữ, tính từ trong các câu văn gần nhau.
`;

const getRegionDescription = (region: string) => {
  switch (region) {
    case 'north': return 'Giọng Miền Bắc (Hà Nội), thanh lịch, nhẹ nhàng.';
    case 'south': return 'Giọng Miền Nam (Sài Gòn), năng động, gần gũi.';
    case 'central': return 'Giọng Miền Trung (Huế/Đà Nẵng), truyền cảm.';
    case 'nghean': return 'Giọng Nghệ An: Mộc mạc, chân chất, sử dụng các từ ngữ địa phương đặc trưng như "chi", "mần", "răng", "rứa", "nỏ", "choa", "rành" một cách tự nhiên.';
    default: return 'Tiếng Việt phổ thông.';
  }
};

/**
 * Transforms an existing script into a new, policy-safe version.
 */
export const rewriteScriptWithAI = async (
  originalScript: string,
  region: string,
  duration: number
): Promise<AIScript> => {
  const prompt = `Bạn là một chuyên gia sáng tạo nội dung kịch bản video. 
  NHIỆM VỤ: Chuyển đổi kịch bản gốc sau đây thành một kịch bản MỚI cho giọng ${region}.

  Kịch bản gốc: "${originalScript}"
  Giọng văn yêu cầu: ${getRegionDescription(region)}.
  Thời lượng mục tiêu: ${duration} giây.

  ${POLICY_INSTRUCTIONS}

  YÊU CẦU:
  1. Phân tích kịch bản gốc để giữ lại ý tưởng chính nhưng viết lại 100% lời thoại.
  2. Tuyệt đối KHÔNG LẶP TỪ ngữ giữa các phân đoạn.
  3. Lách tất cả các từ cấm bằng cách dùng từ đồng nghĩa tinh tế.
  4. Đảm bảo 3s đầu (Hook) cực kỳ cuốn hút theo đúng phong cách giọng ${region}.

  Trả về JSON chuẩn format:
  {
    "title": "Kịch bản chuyển đổi - Giọng ${region}",
    "scenes": [
      {"time": "0:00 - 0:05", "section": "HOOK", "visual": "mô tả hình ảnh mới", "audio": "lời thoại mới an toàn"},
      ...
    ],
    "isSafe": true
  }`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          scenes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                time: { type: Type.STRING },
                section: { type: Type.STRING },
                visual: { type: Type.STRING },
                audio: { type: Type.STRING }
              },
              required: ["time", "section", "visual", "audio"]
            }
          },
          isSafe: { type: Type.BOOLEAN }
        },
        required: ["title", "scenes", "isSafe"]
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

