export const VirtualTryOn: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'preset' | 'upload'>('preset');
  const [modelImage, setModelImage] = useState<ImageAsset | null>(null);
  const [productImage, setProductImage] = useState<ImageAsset | null>(null);

  const categories = Object.keys(OUTFIT_DATABASE);
  const [selectedCategory, setSelectedCategory] = useState(categories[0]);
  const [selectedOutfit, setSelectedOutfit] = useState("");
  const [searchTerm, setSearchTerm] = useState("");
  const [customDescription, setCustomDescription] = useState('');

  const [selectedBackdrop, setSelectedBackdrop] = useState(BACKDROPS[0]);
  const [lighting, setLighting] = useState(LIGHTING_OPTIONS[0]);
  const [filter, setFilter] = useState(FILTER_OPTIONS[0]);
  const [beautyOptions, setBeautyOptions] = useState<string[]>([]);
  const [selectedAspectRatio, setSelectedAspectRatio] = useState(ASPECT_RATIOS[1].id);

  const [resultImage, setResultImage] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const resultRef = useRef<HTMLDivElement>(null);

  const filteredStyles = useMemo(() => {
    const styles = OUTFIT_DATABASE[selectedCategory] || [];
    if (!searchTerm) return styles;
    return styles.filter(style => style.toLowerCase().includes(searchTerm.toLowerCase()));
  }, [selectedCategory, searchTerm]);

  const handleModelUpload = async (file: File) => {
    try {
      const base64 = await fileToBase64(file);
      setModelImage({ id: Date.now().toString(), file, previewUrl: URL.createObjectURL(file), base64, mimeType: getMimeType(file) });
    } catch (e) { alert("Lỗi tải ảnh"); }
  };

  const handleProductUpload = async (file: File) => {
    try {
      const base64 = await fileToBase64(file);
      setProductImage({ id: Date.now().toString(), file, previewUrl: URL.createObjectURL(file), base64, mimeType: getMimeType(file) });
    } catch (e) { alert("Lỗi tải ảnh"); }
  };

  const handleGenerate = async () => {
    if (!modelImage) return;
    setIsGenerating(true);
    setResultImage(null);
    try {
      const desc = activeTab === 'preset' ? (customDescription || selectedOutfit || "Fashionable outfit") : "Reference image clothing";
      const imageUrl = await generateVirtualTryOn(modelImage, desc, lighting, filter, beautyOptions, selectedBackdrop, activeTab === 'upload' ? productImage : null, selectedAspectRatio);
      setResultImage(imageUrl);
      if (window.innerWidth < 1024) resultRef.current?.scrollIntoView({ behavior: 'smooth' });
    } catch (e) { alert("Lỗi xử lý."); } finally { setIsGenerating(false); }
  };

  return (
    <div className="lg:h-full flex flex-col bg-white">
      <div className="flex-1 grid grid-cols-1 lg:grid-cols-12 divide-y lg:divide-y-0 lg:divide-x divide-slate-100 overflow-y-auto lg:overflow-hidden">
          {/* Controls */}
          <div className="lg:col-span-5 p-4 lg:overflow-y-auto custom-scrollbar space-y-6">
              <div className="space-y-4">
                <label className="block text-xs font-black uppercase text-slate-400 tracking-widest"><User size={14} className="inline mr-1"/> 1. Ảnh Người Mẫu</label>
                <UploadBox id="model-upload" label="Ảnh chân dung/toàn thân" image={modelImage} onUpload={handleModelUpload} onRemove={() => setModelImage(null)} heightClass="h-32 lg:h-40" />
              </div>

              <div className="bg-slate-100 p-1 rounded-xl flex gap-1">
                  <button onClick={() => setActiveTab('preset')} className={`flex-1 py-2 rounded-lg text-[11px] font-bold transition-all ${activeTab === 'preset' ? 'bg-white text-orange-600 shadow-sm' : 'text-slate-500'}`}>Mẫu có sẵn</button>
                  <button onClick={() => setActiveTab('upload')} className={`flex-1 py-2 rounded-lg text-[11px] font-bold transition-all ${activeTab === 'upload' ? 'bg-white text-orange-600 shadow-sm' : 'text-slate-500'}`}>Tải đồ lên</button>
              </div>

              {activeTab === 'preset' ? (
                <div className="space-y-4">
                    <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
                        {categories.map((cat) => (
                            <button key={cat} onClick={() => setSelectedCategory(cat)} className={`px-3 py-1.5 rounded-full text-[10px] font-black whitespace-nowrap border transition-all ${selectedCategory === cat ? 'bg-orange-500 text-white border-orange-500' : 'bg-white text-slate-500 border-slate-200'}`}>{cat}</button>
                        ))}
                    </div>
                    <div className="grid grid-cols-1 gap-2 max-h-40 overflow-y-auto custom-scrollbar p-1 border rounded-xl bg-slate-50/50">
                        {filteredStyles.map((style, idx) => (
                            <button key={idx} onClick={() => { setSelectedOutfit(style); setCustomDescription(style); }} className={`p-2 text-left text-[11px] rounded-lg border transition-all ${selectedOutfit === style ? 'bg-orange-100 border-orange-300 text-orange-800 font-bold' : 'bg-white border-slate-100 text-slate-600'}`}>{style}</button>
                        ))}
                    </div>
                </div>
              ) : (
                <UploadBox id="product-upload" label="Ảnh quần áo mẫu" image={productImage} onUpload={handleProductUpload} onRemove={() => setProductImage(null)} heightClass="h-32 lg:h-40" />
              )}

              <button onClick={handleGenerate} disabled={!modelImage || isGenerating} className={`w-full py-4 rounded-xl bg-orange-600 text-white font-black text-xs uppercase tracking-widest shadow-xl shadow-orange-100 active:scale-95 transition-all flex items-center justify-center gap-2 ${isGenerating ? 'opacity-50' : ''}`}>
                  {isGenerating ? <RefreshCw className="animate-spin" /> : <Wand2 size={16} />} Thử đồ ngay
              </button>
          </div>

          {/* Result */}
          <div ref={resultRef} className="lg:col-span-7 bg-slate-50 flex items-center justify-center relative min-h-[400px]">
            {resultImage ? (
                <div className="relative w-full h-full p-4 flex items-center justify-center">
                    <img src={resultImage} alt="Result" className="max-w-full max-h-full object-contain rounded-2xl shadow-2xl" />
                    <button onClick={() => setResultImage(null)} className="absolute top-6 right-6 p-2 bg-white/80 rounded-full shadow-lg text-slate-600"><X size={20}/></button>
                </div>
            ) : (
                <div className="text-center p-10 opacity-20"><Shirt size={64} className="mx-auto mb-3" /><p className="font-black text-xs uppercase tracking-widest">Phòng thử đồ AI</p></div>
            )}
            {isGenerating && <div className="absolute inset-0 bg-white/60 backdrop-blur-sm z-10 flex flex-col items-center justify-center"><Loader2 className="animate-spin text-orange-600 mb-2" size={32} /><p className="text-[10px] font-black uppercase text-orange-700 animate-pulse">AI đang phối đồ...</p></div>}
          </div>
      </div>
    </div>
  );
};

