// Global Policy Instructions for the AI
const POLICY_INSTRUCTIONS = `
TUYÊN THỦ NGHIÊM NGẶT LUẬT POLICY & TIÊU CHUẨN CỘNG ĐỒNG:
1. KHÔNG sử dụng các từ tuyệt đối hóa: "trị dứt điểm", "chữa khỏi", "cam kết 100%", "vĩnh viễn", "tuyệt đối".
2. KHÔNG sử dụng từ liên quan đến y tế/thuốc: thay bằng "sản phẩm", "hỗ trợ", "chuyên gia".
3. KHÔNG sử dụng từ ngữ gây chia rẽ: giàu/nghèo, sang/hèn.
4. GIỌNG VĂN: Luôn tự nhiên, thân thiện, đời thường.
5. KHÔNG LẶP TỪ: Tuyệt đối không lặp lại các tính từ trong các câu văn gần nhau.
`;

export interface AIHookResult {
  category: string;
  hook: string;
}

/**
 * Tạo danh sách tiêu đề HOOK cực lớn và đa dạng
 */
export const generateAIHooks = async (product: string, info: string): Promise<AIHookResult[]> => {
    const prompt = `Tạo một danh sách TIÊU ĐỀ HOOK viral cực lớn cho sản phẩm "${product}" dựa trên thông tin: "${info}".

    SỐ LƯỢNG: Ít nhất 45-55 tiêu đề HOOK.
    CÁC NHÓM CHỦ ĐỀ CẦN CÓ (Mỗi nhóm ít nhất 5-6 hook):
    1. Top (Dạng danh sách: Top 3 lý do, Top 5 sai lầm, Duy nhất 1 cách...)
    2. Secret (Bí mật nhà nghề, Điều shop không nói, Tiết lộ góc khuất)
    3. Curiosity (Gây tò mò, Sự thật ít ai biết, Đừng mua nếu chưa xem)
    4. Pain point (Đánh vào nỗi đau, Vấn đề nan giải, Ám ảnh kinh hoàng)
    5. Trend (Bắt trend, Thử thách 7 ngày, Review quốc dân)
    6. Comparison (So sánh, Đối lập Trước/Sau, Đối thủ vs Tôi)
    7. Feedback (Trải nghiệm thật, Khách hàng nói gì, Cái kết bất ngờ)
    8. Knowledge (Mẹo hay, Kiến thức chuyên sâu, Hướng dẫn tối ưu)
    9. Contrarian (Ngược đời, Phản trực giác, Tại sao tôi lại ghét nó)
    10. Storytelling (Kể chuyện hành trình, Chuyện về con bạn thân)

    ${POLICY_INSTRUCTIONS}

    YÊU CẦU: Trả về mảng JSON [{category: string, hook: string}]. Ngôn ngữ: Tiếng Việt.`;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: { 
                        type: Type.OBJECT,
                        properties: {
                            category: { type: Type.STRING },
                            hook: { type: Type.STRING }
                        },
                        required: ["category", "hook"]
                    }
                }
            }
        });
        return JSON.parse(response.text || '[]');
    } catch (error) {
        console.error("AI Hooks Error:", error);
        return [];
    }
};

/**
 * Ghép người mẫu và sản phẩm - Cam kết giữ nguyên sản phẩm & khuôn mặt
 */
export const generateCompositeImage = async (request: GenerationRequest): Promise<string> => {
  const { personImage, productImage, customBackdrop, outfit, pose, backdrop, expression, aspectRatio, camera } = request;

  let backgroundInstruction = '';
  const parts: any[] = [];

  if (backdrop.id === 'custom_bg' && customBackdrop) {
      backgroundInstruction = `5. BACKGROUND: SỬ DỤNG HÌNH ẢNH 3 LÀM NỀN. Không thay đổi nội dung ảnh 3.`;
  } else if (backdrop.id === 'original_bg') {
      backgroundInstruction = `5. BACKGROUND: GIỮ NGUYÊN bối cảnh từ Ảnh 1.`;
  } else {
      backgroundInstruction = `5. BACKGROUND: Thay thế nền bằng: ${backdrop.prompt}.`;
  }

  const promptText = `
    ROLE: Commercial Photo Compositor.
    YÊU CẦU:
    1. SẢN PHẨM (ẢNH 2): GIỮ NGUYÊN 100%. Không đổi logo, màu sắc.
    2. NGƯỜI MẪU (ẢNH 1): Sử dụng 100% khuôn mặt từ Ảnh 1. Bảo toàn gương mặt tự nhiên.
    3. ĐỘ CHÂN THỰC: 8K, photorealistic.
    ${expression.id === 'keep' ? '' : `Đổi biểu cảm: "${expression.prompt}".`}
    ${outfit.id === 'keep' ? '' : `Mặc trang phục: ${outfit.label}.`}
    ${backgroundInstruction}
    ${camera && camera.id !== 'standard' ? `GÓC MÁY: ${camera.prompt}` : ''}
  `;

  parts.push({ text: promptText });
  parts.push({ inlineData: { mimeType: personImage.mimeType, data: personImage.base64 } });
  parts.push({ inlineData: { mimeType: productImage.mimeType, data: productImage.base64 } });

  if (backdrop.id === 'custom_bg' && customBackdrop) {
      parts.push({ inlineData: { mimeType: customBackdrop.mimeType, data: customBackdrop.base64 } });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: parts },
    config: {
      responseModalities: ['IMAGE'],
      imageConfig: { aspectRatio: aspectRatio.id }
    }
  });

  const resPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (resPart) return `data:image/png;base64,${resPart.inlineData.data}`;
  throw new Error("AI không tạo được ảnh.");
};

