/**
 * Giải mã dữ liệu âm thanh raw PCM
 */
export const decodeAudioData = async (base64: string, ctx: AudioContext): Promise<AudioBuffer> => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  const dataInt16 = new Int16Array(bytes.buffer);
  const buffer = ctx.createBuffer(1, dataInt16.length, 24000);
  const channelData = buffer.getChannelData(0);
  for (let i = 0; i < dataInt16.length; i++) {
    channelData[i] = dataInt16[i] / 32768.0;
  }
  return buffer;
};

/**
 * Chuyển đổi AudioBuffer sang file WAV cho trình duyệt tải về
 */
export const audioBufferToWav = (buffer: AudioBuffer): Blob => {
  const length = buffer.length * 2 + 44;
  const view = new DataView(new ArrayBuffer(length));
  view.setUint32(0, 0x46464952, true); view.setUint32(4, length - 8, true); view.setUint32(8, 0x45564157, true);
  view.setUint32(12, 0x20746d66, true); view.setUint32(16, 16, true); view.setUint16(20, 1, true); view.setUint16(22, 1, true);
  view.setUint32(24, buffer.sampleRate, true); view.setUint32(28, buffer.sampleRate * 2, true); view.setUint16(32, 2, true); view.setUint16(34, 16, true);
  view.setUint32(36, 0x61746164, true); view.setUint32(40, length - 44, true);
  const data = buffer.getChannelData(0);
  for (let i = 0; i < data.length; i++) view.setInt16(44 + i * 2, Math.max(-1, Math.min(1, data[i])) * 0x7FFF, true);
  return new Blob([view], { type: 'audio/wav' });
};

